{
  "name": "Cinematic Studio AI",
  "description": "A high-end professional image generator that uses reference images for background, character, pose, and props, combined with precise lighting and camera controls.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ReferenceType = 'background' | 'character' | 'costume' | 'prop' | 'accessories' | 'pose';

export interface ReferenceImage {
  id: ReferenceType;
  label: string;
  dataUrl?: string;
  mimeType?: string;
}

export interface LightingState {
  positions: boolean[]; // 8 positions
}

export interface CameraConfig {
  model: string;
  lens: string;
  orientation: number; // 0-360
}

export interface StudioState {
  references: Record<ReferenceType, ReferenceImage>;
  lighting: LightingState;
  camera: CameraConfig;
  isGenerating: boolean;
  generatedImage?: string;
}

import React, { useState, useCallback } from 'react';
import { Camera, Layers, Sun, RotateCw, Trash2, Download, Wand2, Loader2, Info } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import OrientationSlider from './components/OrientationSlider';
import { generateStudioImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    camera: {
      model: CAMERA_MODELS[0],
      lens: LENSES[2],
      orientation: 0,
    },
    isGenerating: false,
  });

  const [error, setError] = useState<string | null>(null);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl, mimeType },
      }
    }));
  };

  const handleRemove = (type: ReferenceType) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl: undefined, mimeType: undefined },
      }
    }));
  };

  const toggleLight = (index: number) => {
    setState(prev => {
      const newPositions = [...prev.lighting.positions];
      newPositions[index] = !newPositions[index];
      return { ...prev, lighting: { positions: newPositions } };
    });
  };

  const setThreePointLighting = () => {
    // 3-point lighting: Key (Front-Right), Fill (Front-Left), Rim (Back-Left or Back)
    const newPositions = new Array(8).fill(false);
    newPositions[1] = true; // Key: Front-Right
    newPositions[7] = true; // Fill: Front-Left
    newPositions[4] = true; // Rim: Back
    setState(prev => ({ ...prev, lighting: { positions: newPositions } }));
  };

  const handleGenerate = async () => {
    setState(prev => ({ ...prev, isGenerating: true }));
    setError(null);
    try {
      const result = await generateStudioImage(state);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to generate image. Please try again.");
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const downloadImage = () => {
    if (!state.generatedImage) return;
    const link = document.createElement('a');
    link.href = state.generatedImage;
    link.download = `studio-render-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col">
      {/* Header */}
      <header className="border-b border-white/10 p-4 bg-[#0d0d0d] flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Camera className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight text-white">Cinematic Studio AI</h1>
            <p className="text-xs text-white/40 uppercase tracking-widest">Professional Grade Render Engine</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {error && <span className="text-red-400 text-sm animate-pulse">{error}</span>}
          <button
            onClick={handleGenerate}
            disabled={state.isGenerating}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-full font-semibold transition-all shadow-lg shadow-indigo-500/20 ${
              state.isGenerating 
                ? 'bg-white/5 text-white/40 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-500 text-white transform hover:scale-105 active:scale-95'
            }`}
          >
            {state.isGenerating ? (
              <>
                <Loader2 className="w-5 h-5 animate-spin" />
                <span>Generating...</span>
              </>
            ) : (
              <>
                <Wand2 className="w-5 h-5" />
                <span>Generate Masterpiece</span>
              </>
            )}
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar Controls */}
        <aside className="w-[400px] border-r border-white/10 overflow-y-auto bg-[#0d0d0d] flex flex-col p-6 gap-8 pb-12">

          {/* Reference Images Section */}
          <section>
            <div className="flex items-center gap-2 mb-4">
              <Layers className="w-4 h-4 text-indigo-400" />
              <h2 className="text-sm font-semibold uppercase tracking-wider text-white/60">Reference Studio</h2>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {REFERENCE_SLOTS.map((slot) => (
                <ReferenceUploader
                  key={slot.id}
                  slot={slot}
                  dataUrl={state.references[slot.id].dataUrl}
                  onUpload={(data, mime) => handleUpload(slot.id, data, mime)}
                  onRemove={() => handleRemove(slot.id)}
                />
              ))}
            </div>
          </section>

          {/* Lighting Controls */}
          <section>
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2">
                <Sun className="w-4 h-4 text-amber-400" />
                <h2 className="text-sm font-semibold uppercase tracking-wider text-white/60">Lighting Rig</h2>
              </div>
              <button 
                onClick={setThreePointLighting}
                className="text-[10px] bg-white/5 hover:bg-white/10 text-white/60 px-2 py-1 rounded transition-colors"
              >
                Set 3-Point
              </button>
            </div>
            <div className="bg-white/5 rounded-2xl p-6 border border-white/5">
              <LightRig 
                activePositions={state.lighting.positions}
                onToggle={toggleLight}
              />
              <div className="mt-4 flex flex-wrap gap-2 justify-center">
                {LIGHT_POSITIONS.map((lp, i) => (
                  <span key={i} className={`text-[9px] px-1.5 py-0.5 rounded ${state.lighting.positions[i] ? 'bg-amber-500/20 text-amber-400' : 'text-white/20'}`}>
                    {lp.label}
                  </span>
                ))}
              </div>
            </div>
          </section>

          {/* Camera Config */}
          <section>
            <div className="flex items-center gap-2 mb-4">
              <RotateCw className="w-4 h-4 text-emerald-400" />
              <h2 className="text-sm font-semibold uppercase tracking-wider text-white/60">Camera & Orientation</h2>
            </div>
            <div className="space-y-4">
              <div className="bg-white/5 rounded-2xl p-6 border border-white/5">
                <OrientationSlider 
                  value={state.camera.orientation}
                  onChange={(val) => setState(prev => ({ ...prev, camera: { ...prev.camera, orientation: val }}))}
                />
              </div>

              <div className="grid grid-cols-1 gap-4 mt-4">
                <div className="space-y-1.5">
                  <label className="text-xs text-white/40 ml-1">Camera System</label>
                  <select 
                    value={state.camera.model}
                    onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, model: e.target.value }}))}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-indigo-500 transition-colors appearance-none text-white"
                  >
                    {CAMERA_MODELS.map(m => <option key={m} value={m} className="bg-[#1a1a1a]">{m}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-xs text-white/40 ml-1">Focal Length</label>
                  <select 
                    value={state.camera.lens}
                    onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, lens: e.target.value }}))}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-indigo-500 transition-colors appearance-none text-white"
                  >
                    {LENSES.map(l => <option key={l} value={l} className="bg-[#1a1a1a]">{l}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </section>
        </aside>

        {/* Output Area */}
        <section className="flex-1 bg-black relative flex flex-col items-center justify-center p-8 overflow-hidden">
          <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at center, #312e81 0%, transparent 70%)' }}></div>

          {!state.generatedImage && !state.isGenerating ? (
            <div className="text-center max-w-md animate-in fade-in duration-700">
              <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-6 border border-white/10">
                <Camera className="w-10 h-10 text-white/20" />
              </div>
              <h3 className="text-2xl font-bold mb-3 text-white">Ready for Capture</h3>
              <p className="text-white/40 text-sm leading-relaxed">
                Configure your references, lighting, and camera settings in the sidebar. 
                Hit "Generate Masterpiece" to render your cinematic image using Gemini AI.
              </p>
              <div className="mt-8 flex items-start gap-4 p-4 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 text-left">
                <Info className="w-5 h-5 text-indigo-400 shrink-0 mt-0.5" />
                <p className="text-[11px] text-indigo-300 leading-normal">
                  Pro-tip: For best results, provide both a Character and Background reference. Lighting adjustments are most visible on high-contrast scenes.
                </p>
              </div>
            </div>
          ) : state.isGenerating ? (
            <div className="flex flex-col items-center gap-6 z-10">
              <div className="relative">
                <div className="w-32 h-32 border-4 border-indigo-500/20 rounded-full animate-spin"></div>
                <div className="w-32 h-32 border-t-4 border-indigo-500 rounded-full absolute top-0 animate-spin"></div>
                <Camera className="w-8 h-8 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
              </div>
              <div className="text-center space-y-2">
                <p className="text-xl font-medium text-white tracking-wide">Processing Reference Assets</p>
                <p className="text-white/40 text-sm animate-pulse">Running neural lighting simulations...</p>
              </div>
            </div>
          ) : (
            <div className="relative group w-full h-full flex items-center justify-center animate-in zoom-in-95 duration-500">
              <div className="max-w-full max-h-full rounded-2xl overflow-hidden shadow-2xl border border-white/10">
                <img 
                  src={state.generatedImage} 
                  alt="Generated" 
                  className="max-w-full max-h-[80vh] object-contain"
                />
              </div>

              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex gap-3 opacity-0 group-hover:opacity-100 transition-opacity duration-300 translate-y-4 group-hover:translate-y-0">
                <button 
                  onClick={downloadImage}
                  className="flex items-center gap-2 bg-white text-black px-6 py-3 rounded-full font-bold hover:bg-white/90 transition-all shadow-xl"
                >
                  <Download className="w-5 h-5" />
                  Download PNG
                </button>
                <button 
                  onClick={() => setState(prev => ({ ...prev, generatedImage: undefined }))}
                  className="bg-white/10 backdrop-blur-md hover:bg-white/20 text-white p-3 rounded-full transition-all border border-white/20"
                >
                  <Trash2 className="w-6 h-6" />
                </button>
              </div>
            </div>
          )}
        </section>
      </main>

      {/* Status Bar */}
      <footer className="h-8 border-t border-white/5 bg-[#080808] px-4 flex items-center justify-between text-[10px] text-white/30 uppercase tracking-[0.2em]">
        <div className="flex gap-4">
          <span>Engine: Gemini-2.5-Flash-Image</span>
          <span className="text-white/10">|</span>
          <span>Status: Standby</span>
        </div>
        <div>
          © 2024 Cinematic Studio AI • v1.0.4-Alpha
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { Upload, X, Image as ImageIcon } from 'lucide-react';
import { ReferenceType } from '../types';

interface ReferenceUploaderProps {
  slot: { id: ReferenceType; label: string };
  dataUrl?: string;
  onUpload: (dataUrl: string, mimeType: string) => void;
  onRemove: () => void;
}

const ReferenceUploader: React.FC<ReferenceUploaderProps> = ({ slot, dataUrl, onUpload, onRemove }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const result = event.target?.result as string;
        onUpload(result, file.type);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div 
      className={`relative group rounded-xl overflow-hidden aspect-square border-2 border-dashed transition-all ${
        dataUrl 
          ? 'border-indigo-500/50 bg-[#1a1a1a]' 
          : 'border-white/5 hover:border-white/20 bg-white/5'
      }`}
    >
      {dataUrl ? (
        <>
          <img src={dataUrl} alt={slot.label} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex flex-col items-center justify-center transition-opacity gap-2 p-2">
            <span className="text-[10px] text-white font-medium text-center">{slot.label}</span>
            <button 
              onClick={onRemove}
              className="bg-red-500/80 hover:bg-red-500 text-white p-1.5 rounded-full transition-colors"
            >
              <X className="w-3.5 h-3.5" />
            </button>
          </div>
        </>
      ) : (
        <label className="flex flex-col items-center justify-center h-full cursor-pointer p-4 text-center group">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleChange} 
            className="hidden" 
            accept="image/*"
          />
          <div className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center mb-3 group-hover:bg-indigo-500/20 group-hover:text-indigo-400 transition-colors text-white/20">
            <Upload className="w-5 h-5" />
          </div>
          <span className="text-[10px] text-white/40 font-semibold tracking-wider uppercase group-hover:text-white/60 transition-colors">
            {slot.label}
          </span>
          <span className="text-[9px] text-white/20 mt-1">Upload Ref</span>
        </label>
      )}
    </div>
  );
};

export default ReferenceUploader;

import React from 'react';
import { LIGHT_POSITIONS } from '../constants';

interface LightRigProps {
  activePositions: boolean[];
  onToggle: (index: number) => void;
}

const LightRig: React.FC<LightRigProps> = ({ activePositions, onToggle }) => {
  return (
    <div className="relative w-40 h-40 mx-auto">
      {/* Center Character Indicator */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-12 h-12 bg-indigo-500/20 rounded-full flex items-center justify-center border border-indigo-500/40">
        <div className="w-3 h-4 bg-white/40 rounded-t-full rounded-b-sm"></div>
      </div>

      {/* Ring Background */}
      <div className="absolute inset-0 border border-white/5 rounded-full"></div>

      {/* 8 Light Switchers */}
      {LIGHT_POSITIONS.map((lp, i) => {
        // Calculate position on the circle
        const angleRad = (lp.angle - 90) * (Math.PI / 180);
        const radius = 70; // px
        const x = 80 + radius * Math.cos(angleRad);
        const y = 80 + radius * Math.sin(angleRad);

        return (
          <button
            key={i}
            onClick={() => onToggle(i)}
            style={{ left: x, top: y }}
            className={`absolute -translate-x-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center transition-all border ${
              activePositions[i]
                ? 'bg-amber-500 border-amber-400 shadow-lg shadow-amber-500/50 scale-110'
                : 'bg-white/5 border-white/10 hover:bg-white/10'
            }`}
          >
            <div className={`w-1.5 h-1.5 rounded-full ${activePositions[i] ? 'bg-white' : 'bg-white/20'}`}></div>
            {/* Visual Light Beam Ray */}
            {activePositions[i] && (
              <div 
                className="absolute w-20 h-12 bg-gradient-to-r from-amber-500/40 to-transparent pointer-events-none"
                style={{ 
                  transform: `rotate(${lp.angle + 180}deg)`, 
                  transformOrigin: '0% 50%',
                  clipPath: 'polygon(0% 40%, 100% 0%, 100% 100%, 0% 60%)'
                }}
              ></div>
            )}
          </button>
        );
      })}
    </div>
  );
};

export default LightRig;

import React from 'react';
import { Compass } from 'lucide-react';

interface OrientationSliderProps {
  value: number;
  onChange: (val: number) => void;
}

const OrientationSlider: React.FC<OrientationSliderProps> = ({ value, onChange }) => {
  return (
    <div className="flex flex-col items-center gap-4">
      <div className="relative w-32 h-32 rounded-full border-2 border-white/10 flex items-center justify-center overflow-hidden bg-black/40">
        {/* Compass Marks */}
        <div className="absolute inset-2 border border-white/5 rounded-full pointer-events-none"></div>
        <div className="absolute h-full w-px bg-white/5 left-1/2 -translate-x-1/2"></div>
        <div className="absolute w-full h-px bg-white/5 top-1/2 -translate-y-1/2"></div>

        {/* Indicator */}
        <div 
          className="absolute w-12 h-12 flex items-center justify-center transition-transform duration-200"
          style={{ transform: `rotate(${value}deg)` }}
