          <div className="w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-b-[20px] border-b-indigo-500 drop-shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
        </div>

        <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent pointer-events-none"></div>
      </div>

      <div className="w-full space-y-2">
        <div className="flex justify-between items-center text-[10px] text-white/40 uppercase tracking-widest px-1">
