export default OrientationSlider;

import { GoogleGenAI } from "@google/genai";
import { StudioState, ReferenceType } from "../types";
import { LIGHT_POSITIONS } from "../constants";

export const generateStudioImage = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Collect uploaded images
  const referenceParts: any[] = [];
  const descriptions: string[] = [];

  Object.values(state.references).forEach(ref => {
    if (ref.dataUrl && ref.mimeType) {
      const base64Data = ref.dataUrl.split(',')[1];
      referenceParts.push({
        inlineData: {
          data: base64Data,
          mimeType: ref.mimeType,
        },
      });
      descriptions.push(`- The ${ref.label} reference image.`);
    }
  });

  // Calculate Lighting Prompt
  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const lightingPrompt = activeLights.length > 0 
    ? `The scene is lit with ${activeLights.join(', ')} light sources, creating professional cinematic shadows and highlights.` 
    : 'Use natural studio lighting.';

  // Construct Final Prompt
  const prompt = `
    TASK: Generate a high-end, professional cinematic render following these strict specifications.

    REFERENCE IMAGES PROVIDED:
    ${descriptions.join('\n')}
    (Please meticulously use the character, background, costume, and pose from these images as exact references for the final output).

    SCENE & SUBJECT:
    - Orientation: The main character is oriented at a ${state.camera.orientation} degree angle relative to the camera lens.
    - Style: Photorealistic cinematic masterpiece.
    - Lighting: ${lightingPrompt}

    CAMERA SPECIFICATIONS:
    - Body: ${state.camera.model} digital cinema camera sensor characteristics.
    - Lens: ${state.camera.lens} focal length, providing precise depth of field, realistic bokeh, and optical character.
    - Resolution: High fidelity detail in textures, skin pores, and fabric weaves.

    INSTRUCTIONS:
    - Seamlessly blend all provided reference elements into a single cohesive frame.
    - Maintain the likeness of the character and the environment of the background.
    - Ensure the lighting rig selected (${activeLights.join(', ')}) correctly interacts with the geometry of the subjects.
    - Strictly adhere to the ${state.camera.lens} aesthetic.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          ...referenceParts,
          { text: prompt.trim() }
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    let generatedImageUrl = '';
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        generatedImageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    if (!generatedImageUrl) {
      throw new Error("No image was generated by the model. The prompt might have been blocked or the references were too complex.");
    }

    return generatedImageUrl;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Camera, Layers, Sun, RotateCw, Trash2, Download, Wand2, Loader2, Info, Settings2 } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import OrientationSlider from './components/OrientationSlider';
import { generateStudioImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    camera: {
      model: CAMERA_MODELS[0],
      lens: LENSES[2],
      orientation: 0,
    },
    isGenerating: false,
  });

  const [error, setError] = useState<string | null>(null);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl, mimeType },
      }
    }));
  };

  const handleRemove = (type: ReferenceType) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl: undefined, mimeType: undefined },
      }
    }));
  };

  const toggleLight = (index: number) => {
    setState(prev => {
      const newPositions = [...prev.lighting.positions];
      newPositions[index] = !newPositions[index];
      return { ...prev, lighting: { positions: newPositions } };
    });
  };

  const setThreePointLighting = () => {
    const newPositions = new Array(8).fill(false);
    newPositions[1] = true; 
    newPositions[7] = true; 
    newPositions[4] = true; 
    setState(prev => ({ ...prev, lighting: { positions: newPositions } }));
  };

  const handleGenerate = async () => {
    setState(prev => ({ ...prev, isGenerating: true }));
    setError(null);
    try {
      const result = await generateStudioImage(state);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
      // On mobile, scroll to top to see the image
      if (window.innerWidth < 1024) {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Generation failed.");
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const downloadImage = () => {
    if (!state.generatedImage) return;
    const link = document.createElement('a');
    link.href = state.generatedImage;
    link.download = `studio-render-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col">
      {/* Header */}
      <header className="border-b border-white/10 p-4 bg-[#0d0d0d]/90 backdrop-blur-md flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2 lg:gap-3">
          <div className="bg-indigo-600 p-1.5 lg:p-2 rounded-lg">
            <Camera className="w-5 h-5 lg:w-6 lg:h-6 text-white" />
          </div>
          <div>
            <h1 className="text-sm lg:text-xl font-bold tracking-tight text-white leading-none">Cinematic Studio</h1>
            <p className="text-[8px] lg:text-xs text-white/40 uppercase tracking-widest mt-0.5">AI Render Engine</p>
          </div>
        </div>

        <div className="flex items-center gap-2 lg:gap-4">
          {error && <span className="hidden sm:inline text-red-400 text-xs animate-pulse truncate max-w-[150px]">{error}</span>}
          <button
            onClick={handleGenerate}
            disabled={state.isGenerating}
            className={`flex items-center gap-2 px-4 lg:px-6 py-2 lg:py-2.5 rounded-full text-xs lg:text-sm font-semibold transition-all shadow-lg shadow-indigo-500/20 ${
              state.isGenerating 
                ? 'bg-white/5 text-white/40 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-500 text-white transform active:scale-95'
            }`}
          >
            {state.isGenerating ? (
              <Loader2 className="w-4 h-4 lg:w-5 lg:h-5 animate-spin" />
            ) : (
              <Wand2 className="w-4 h-4 lg:w-5 lg:h-5" />
            )}
            <span className="hidden xs:inline">{state.isGenerating ? 'Rendering...' : 'Render'}</span>
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:flex-row lg:overflow-hidden">
        {/* Output Area - First on Mobile */}
        <section className="order-1 lg:order-2 flex-1 bg-black relative flex flex-col items-center justify-center p-4 lg:p-8 min-h-[350px] lg:min-h-0">
          <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at center, #312e81 0%, transparent 70%)' }}></div>

          {!state.generatedImage && !state.isGenerating ? (
            <div className="text-center max-w-md p-6">
              <div className="w-16 h-16 lg:w-24 lg:h-24 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4 lg:mb-6 border border-white/10">
                <Camera className="w-8 h-8 lg:w-10 lg:h-10 text-white/20" />
              </div>
              <h3 className="text-xl lg:text-2xl font-bold mb-2 text-white">Capture Point</h3>
              <p className="text-white/40 text-xs lg:text-sm leading-relaxed mb-6">
                Ready for your cinematic vision. Configure the studio settings below.
              </p>
              <div className="hidden lg:flex items-start gap-4 p-4 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 text-left">
                <Info className="w-5 h-5 text-indigo-400 shrink-0 mt-0.5" />
                <p className="text-[11px] text-indigo-300">
                  Combine character and background references for optimal results.
                </p>
              </div>
            </div>
          ) : state.isGenerating ? (
            <div className="flex flex-col items-center gap-4 lg:gap-6 z-10 text-center">
              <div className="relative">
                <div className="w-24 h-24 lg:w-32 lg:h-32 border-4 border-indigo-500/20 rounded-full animate-spin"></div>
                <div className="w-24 h-24 lg:w-32 lg:h-32 border-t-4 border-indigo-500 rounded-full absolute top-0 animate-spin"></div>
                <Camera className="w-6 h-6 lg:w-8 lg:h-8 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
              </div>
              <div className="space-y-1">
                <p className="text-lg lg:text-xl font-medium text-white tracking-wide">Synthesizing Assets</p>
                <p className="text-white/40 text-[10px] lg:text-xs animate-pulse">Calculating lighting vectors...</p>
              </div>
            </div>
          ) : (
            <div className="relative group w-full h-full flex flex-col items-center justify-center animate-in zoom-in-95 duration-500">
              <div className="max-w-full max-h-full rounded-xl lg:rounded-2xl overflow-hidden shadow-2xl border border-white/10">
                <img 
                  src={state.generatedImage} 
                  alt="Generated" 
                  className="max-w-full max-h-[60vh] lg:max-h-[80vh] object-contain"
                />
              </div>

              <div className="mt-6 flex gap-3 lg:absolute lg:bottom-8 lg:left-1/2 lg:-translate-x-1/2 lg:opacity-0 lg:group-hover:opacity-100 lg:transition-opacity lg:duration-300 lg:translate-y-4 lg:group-hover:translate-y-0">
                <button 
                  onClick={downloadImage}
