export type ReferenceType = 'background' | 'character' | 'costume' | 'prop' | 'accessories' | 'pose';

export interface ReferenceImage {
  id: ReferenceType;
  label: string;
  dataUrl?: string;
  mimeType?: string;
}

export interface LightingState {
  positions: boolean[]; // 8 positions
}

export interface CameraConfig {
  model: string;
  lens: string;
  shotScale: string;
  orientation: number; // 0-360
}

export interface StudioState {
  references: Record<ReferenceType, ReferenceImage>;
  lighting: LightingState;
