import { GoogleGenAI } from "@google/genai";
import { StudioState, ReferenceType } from "../types";
import { LIGHT_POSITIONS } from "../constants";

export const generateStudioImage = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Collect uploaded images
  const referenceParts: any[] = [];
  const descriptions: string[] = [];

  Object.values(state.references).forEach(ref => {
    if (ref.dataUrl && ref.mimeType) {
      const base64Data = ref.dataUrl.split(',')[1];
      referenceParts.push({
        inlineData: {
          data: base64Data,
          mimeType: ref.mimeType,
        },
      });
      descriptions.push(`- The ${ref.label} reference image.`);
    }
  });

  // Calculate Lighting Prompt
  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const lightingPrompt = activeLights.length > 0 
    ? `The scene is meticulously lit with ${activeLights.join(', ')} light sources, creating professional cinematic depth, shadows, and highlights typical of high-budget film productions.` 
    : 'Use high-contrast professional studio lighting.';

  // Construct Final Prompt
  const prompt = `
    TASK: Generate a world-class, professional cinematic render following these strict cinematography specifications.

    REFERENCE IMAGES PROVIDED:
    ${descriptions.join('\n')}
    (CRITICAL: Meticulously use the character, background, costume, and pose from these provided reference images. The final output must be a seamless blend of these assets).

    COMPOSITION & FRAMING:
    - Shot Scale: This is a ${state.camera.shotScale}. Ensure the framing matches this exact cinematography standard.
    - Orientation: The main subject is positioned at a ${state.camera.orientation} degree rotational angle relative to the camera's optical axis.
    - Style: Photorealistic, cinematic, hyper-detailed.

    LIGHTING RIG:
    - Configuration: ${lightingPrompt}

    CAMERA & OPTICS:
    - Camera Body: Characteristics of the ${state.camera.model} sensor (color science, dynamic range).
    - Lens Selection: ${state.camera.lens}. Render realistic depth of field, appropriate lens flares, and subtle chromatic aberration consistent with this specific focal length.
    - Technical Quality: 8K resolution, high fidelity textures, natural skin renders, and professional color grading.

    FINAL DIRECTIVE:
    Integrate the references into a single, cohesive, breathtaking image that looks like a still from a blockbuster movie.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          ...referenceParts,
          { text: prompt.trim() }
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    let generatedImageUrl = '';
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        generatedImageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    if (!generatedImageUrl) {
      throw new Error("Generation failed. Please check your reference images and try again.");
    }

    return generatedImageUrl;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export type ReferenceType = 'background' | 'character' | 'costume' | 'prop' | 'accessories' | 'pose';

export interface ReferenceImage {
  id: ReferenceType;
  label: string;
  dataUrl?: string;
  mimeType?: string;
}

export interface LightingState {
  positions: boolean[]; // 8 positions
}

export interface CameraConfig {
  model: string;
  lens: string;
  shotScale: string;
  orientation: number; // 0-360
}

export interface StudioState {
  references: Record<ReferenceType, ReferenceImage>;
  lighting: LightingState;
  camera: CameraConfig;
  isGenerating: boolean;
  isGeneratingPrompt: boolean;
  isReviewingPrompt: boolean;
  draftPrompt: string;
  generatedImage?: string;
}

import { GoogleGenAI } from "@google/genai";
import { StudioState } from "../types";
import { LIGHT_POSITIONS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  // Collect uploaded images metadata
  const descriptions: string[] = [];
  Object.values(state.references).forEach(ref => {
    if (ref.dataUrl) {
      descriptions.push(`- ${ref.label} reference provided.`);
    }
  });

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const lightingStr = activeLights.length > 0 
    ? `Lighting setup: ${activeLights.join(', ')}.` 
    : 'Natural studio lighting.';

  const systemInstruction = "You are a professional cinematographic prompt engineer for high-end AI image generators. Your goal is to write a single, dense, descriptive paragraph that translates technical studio settings into a poetic yet technical visual prompt.";

  const prompt = `
    Generate a high-end cinematic image prompt based on:
    SHOT TYPE: ${state.camera.shotScale}
    CAMERA: ${state.camera.model} with ${state.camera.lens} lens.
    ORIENTATION: Subject is at ${state.camera.orientation} degrees to camera.
    LIGHTING: ${lightingStr}
    REFERENCES: ${descriptions.length > 0 ? descriptions.join(', ') : 'No image references provided, describe a generic cinematic hero.'}

    REQUIREMENTS:
    1. Focus on textures, lighting behavior (rim lights, soft shadows), and atmospheric quality.
    2. Mention the lens characteristics (bokeh, depth of field).
    3. The prompt should be about 100-150 words.
    4. Do not use Markdown, just return the raw text.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt.trim(),
      config: {
        systemInstruction,
      }
    });
    return response.text || "Cinematic masterpiece render...";
  } catch (error) {
    console.error("Prompt Generation Error:", error);
    return "A high-end cinematic masterpiece render featuring professional studio lighting and precise camera optics.";
  }
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  // Collect uploaded images for multi-modal input
