          data: base64Data,
          mimeType: ref.mimeType,
        },
      });
    }
  });

  const wrappedPrompt = `
    FOLLOW THESE REFERENCE IMAGES STRICTLY.
    FINAL PROMPT: ${finalPrompt}
    TECHNICAL QUALITY: 8K resolution, hyper-detailed textures, photorealistic render.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
