  const lightingStr = activeLights.length > 0 
    ? `Lighting setup: ${activeLights.join(', ')}.` 
    : 'Professional studio lighting.';

  const systemInstruction = `You are a world-class Cinematography Concept Artist and Prompt Engineer.

  YOUR GOAL: 
  Generate a single, cohesive, and extremely detailed cinematographic prompt based on provided reference images and technical settings.

  CORE RULES:
  1. Identify the 'Character' and 'Costume' images and describe their unique features (face shape, hair, fabric texture, specific embroidery, armor patterns) EXACTLY as seen.
