  5. The output must be a descriptive paragraph (approx 150 words) designed for a high-end image generator.
  6. Return ONLY the final prompt text. No "Here is your prompt" or markdown.`;

  const userRequest = `
    Technical Settings:
    - Shot Scale: ${state.camera.shotScale}
    - Optics: ${state.camera.model} with ${state.camera.lens} lens
    - Rotation: ${state.camera.orientation} degrees relative to camera
    - Lighting: ${lightingStr}

