      config: {
        systemInstruction,
        temperature: 1,
      }
    });

    return response.text?.trim() || "A cinematic render combining provided references.";
  } catch (error) {
    console.error("Prompt Generation Error:", error);
    throw new Error("Failed to generate descriptive prompt. Try reducing image sizes or number of references.");
