import { GoogleGenAI } from "@google/genai";
import { StudioState } from "../types";
import { LIGHT_POSITIONS } from "../constants";

/**
 * Utility to aggressively downscale images to prevent payload size errors (500 XHR errors).
 * We use a smaller maxWidth and lower quality to stay well under proxy limits.
 */
async function downscaleImage(dataUrl: string, maxWidth = 448, quality = 0.5): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));

      // Use a background fill to ensure no transparency issues with JPEG
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      // Convert to JPEG with reduced quality to significantly cut down byte size
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      const base64 = scaledDataUrl.split(',')[1];
      resolve({ data: base64, mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Failed to load image for downscaling"));
    img.src = dataUrl;
  });
}

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const parts: any[] = [];
  const referenceRoles: string[] = [];

  // We only send images that are set. For prompt generation, 448px is enough for visual understanding.
  for (const [id, ref] of Object.entries(state.references)) {
    if (ref.dataUrl && ref.mimeType) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 448, 0.5);
        parts.push({ text: `REFERENCE_${ref.id.toUpperCase()}: This is the ${ref.label} reference.` });
        parts.push({
          inlineData: { data, mimeType },
        });
        referenceRoles.push(ref.label);
      } catch (e) {
        console.warn(`Failed to process reference ${ref.label}`, e);
      }
    }
  }

  const activeLights = state.lighting.positions
    .map((active, i) => {
      if (!active) return null;
      const pos = LIGHT_POSITIONS[i];
      let role = "Studio Light";
      if (pos.label.includes("Back")) role = "High-intensity Rim Light";
      else if (pos.label === "Front") role = "Soft Key Light";
      else if (pos.label.includes("Left") || pos.label.includes("Right")) role = "Side Fill/Kick Light";
      return `${pos.label} (${role})`;
    })
    .filter(Boolean);

  const lightingStr = activeLights.length > 0 
    ? `Additional Studio Lights: ${activeLights.join(', ')}.` 
    : 'No additional studio lights; relying purely on environmental ambient.';

  const systemInstruction = `You are a world-class Cinematography Concept Artist and Lighting Technical Director.

  YOUR GOAL: 
  Generate a single, cohesive, and extremely detailed cinematographic prompt.

  INTEGRATION RULES (CRITICAL):
  1. AMBIENT BASE: First, analyze the 'Background' reference for its dominant color temperature, ambient light direction, and global illumination. Instruct the renderer to "color-match" and "ambient-integrate" the character into this environment. The character's skin and costume must absorb the background's light tones (e.g., if the background is a sunset, the character should have a warm orange ambient wash).
  2. STUDIO LAYER: Apply the user's selected studio lights (${lightingStr}) ON TOP of the ambient base. Describe these as motivated light sources that create depth, rim highlights, and professional contrast while respecting the background's existence.
  3. CHARACTER FAITHFULNESS: Describe the 'Character' and 'Costume' features (face, textures, specific patterns) exactly as seen in the references.
  4. PHYSICS: Ensure realistic contact shadows between the character and the background floor/surfaces.

  TECHNICAL DETAILS:
  - Use camera specs: ${state.camera.model}, ${state.camera.lens}.
  - Framing: ${state.camera.shotScale}.
  - Describe specific lighting behaviors: subsurface scattering on skin, specular highlights on fabrics, and environmental reflections.

  OUTPUT:
  Return ONLY the descriptive paragraph (approx 150-200 words). No preamble.`;

  const userRequest = `
    Technical Settings:
    - Shot Scale: ${state.camera.shotScale}
    - Optics: ${state.camera.model} with ${state.camera.lens} lens
    - Rotation: Character is rotated ${state.camera.orientation} degrees relative to the camera lens.
    - Lighting: ${lightingStr}

    References provided: ${referenceRoles.join(', ')}.

    Task: Write the render prompt. Ensure the character feels physically present and perfectly light-integrated into the background.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          ...parts,
          { text: userRequest.trim() }
        ]
      },
      config: {
        systemInstruction,
        temperature: 0.8,
      }
    });

    return response.text?.trim() || "A cinematic render combining provided references with integrated lighting.";
  } catch (error) {
    console.error("Prompt Generation Error:", error);
    throw new Error("Failed to generate descriptive prompt. The request payload might still be too large—try removing one or two non-essential reference images.");
  }
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const parts: any[] = [];
  for (const ref of Object.values(state.references)) {
    if (ref.dataUrl && ref.mimeType) {
      try {
        // For image generation guidance, 384px is enough for most features while keeping the total payload small.
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 384, 0.5);
        parts.push({
          inlineData: { data, mimeType },
        });
      } catch (e) {
        console.warn(`Failed to process reference ${ref.label}`, e);
      }
    }
  }

  const prompt = `
    MASTER RENDER INSTRUCTION:
    - You are provided with several visual references for character, costume, background, and props.
    - You MUST perfectly integrate the CHARACTER from the references into the BACKGROUND environment.
    - AMBIENT MATCHING: The character's lighting must be color-graded to match the background's global illumination as a base. If the background is dark/moody, the character must be too.
    - COMPOSITING: Use the following description for the final shot: ${finalPrompt}
    - QUALITY: Hyper-realistic, cinematic, 8K, realistic physics, seamless light interaction, masterfully composited.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          ...parts,
          { text: prompt.trim() }
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data returned from model.");
  } catch (error: any) {
    console.error("Image Generation Error:", error);
    if (error.message?.includes('500') || error.message?.includes('Rpc failed')) {
      throw new Error("Image Generation Failed: The total size of your reference images is too large for the processing gateway. Please try removing 1-2 reference images to reduce the payload.");
    }
    throw error;
  }
};

