    if (ref.dataUrl && ref.mimeType) {
      try {
        // For image generation guidance, 256px is sufficient to guide the latent space while keeping bytes minimal.
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
        parts.push({
          inlineData: { data, mimeType },
        });
      } catch (e) {
        console.warn(`Failed to process reference ${ref.label}`, e);
      }
    }
  }

  const prompt = `
    INSTRUCTION: Render a scene where the CHARACTER and COSTUME are perfectly integrated into the BACKGROUND.
    AMBIENT HARMONY: The character must inherit the exact color temperature and light intensity of the background environment.
    COMPOSITING: ${finalPrompt}
    QUALITY: Photorealistic, cinematic, 8K, realistic skin shaders, depth of field, seamless integration.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          ...parts,
          { text: prompt.trim() }
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data returned.");
  } catch (error: any) {
    console.error("Image Generation Error:", error);
    if (error.message?.includes('500') || error.message?.includes('Rpc failed')) {
      throw new Error("Server Error: The request payload is still too large. Please remove 1-2 optional reference images (like Props or Accessories) and try again.");
    }
    throw error;
  }
};

