import React, { useState } from 'react';
import { Camera, Layers, Sun, Trash2, Download, Wand2, Loader2, Info, Settings2, Copy, Check, X, FileText, RotateCw } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS, SHOT_SCALES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import OrientationSlider from './components/OrientationSlider';
import ShotScalePicker from './components/ShotScalePicker';
import { generateDraftPrompt, generateStudioImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    camera: {
      model: CAMERA_MODELS[0],
      lens: LENSES[2],
      shotScale: SHOT_SCALES[3].label,
      orientation: 0,
    },
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    draftPrompt: '',
  });

  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl, mimeType },
      }
    }));
  };

  const handleRemove = (type: ReferenceType) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl: undefined, mimeType: undefined },
      }
    }));
  };

  const toggleLight = (index: number) => {
    setState(prev => {
      const newPositions = [...prev.lighting.positions];
      newPositions[index] = !newPositions[index];
      return { ...prev, lighting: { positions: newPositions } };
    });
  };

  const setThreePointLighting = () => {
    const newPositions = new Array(8).fill(false);
    newPositions[1] = true; 
    newPositions[7] = true; 
    newPositions[4] = true; 
    setState(prev => ({ ...prev, lighting: { positions: newPositions } }));
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    setError(null);
    try {
      const prompt = await generateDraftPrompt(state);
      setState(prev => ({ 
        ...prev, 
        draftPrompt: prompt, 
        isGeneratingPrompt: false, 
        isReviewingPrompt: true 
      }));
    } catch (err: any) {
      setError(err.message || "Failed to generate prompt.");
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    setError(null);
    try {
      const result = await generateStudioImage(state, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
      if (window.innerWidth < 1024) {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    } catch (err: any) {
      setError(err.message || "Generation failed.");
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(state.draftPrompt);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const downloadImage = () => {
    if (!state.generatedImage) return;
    const link = document.createElement('a');
    link.href = state.generatedImage;
    link.download = `studio-render-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col">
      {/* Header */}
      <header className="border-b border-white/10 p-4 bg-[#0d0d0d]/90 backdrop-blur-md flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2 lg:gap-3">
          <div className="bg-indigo-600 p-1.5 lg:p-2 rounded-lg">
            <Camera className="w-5 h-5 lg:w-6 lg:h-6 text-white" />
          </div>
          <div>
            <h1 className="text-sm lg:text-xl font-bold tracking-tight text-white leading-none">Cinematic Studio</h1>
            <p className="text-[8px] lg:text-xs text-white/40 uppercase tracking-widest mt-0.5">AI Render Engine</p>
          </div>
        </div>

        <div className="flex items-center gap-2 lg:gap-4">
          {error && <span className="hidden sm:inline text-red-400 text-xs animate-pulse truncate max-w-[150px]">{error}</span>}

          {!state.isReviewingPrompt && !state.generatedImage && (
            <button
              onClick={handleGeneratePrompt}
              disabled={state.isGeneratingPrompt}
              className={`flex items-center gap-2 px-4 lg:px-6 py-2 lg:py-2.5 rounded-full text-xs lg:text-sm font-semibold transition-all shadow-lg shadow-indigo-500/20 ${
                state.isGeneratingPrompt 
                  ? 'bg-white/5 text-white/40 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-500 text-white transform active:scale-95'
              }`}
            >
              {state.isGeneratingPrompt ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Wand2 className="w-4 h-4" />
              )}
              <span className="hidden xs:inline">{state.isGeneratingPrompt ? 'Thinking...' : 'Generate Prompt'}</span>
            </button>
          )}

          {state.isReviewingPrompt && (
            <button
              onClick={handleFinalRender}
              className="flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-bold bg-emerald-600 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-500/20 transform active:scale-95 transition-all animate-pulse"
            >
              <Check className="w-4 h-4" />
              <span>Confirm & Render</span>
            </button>
          )}

          {state.generatedImage && (
            <button
              onClick={() => setState(prev => ({ ...prev, generatedImage: undefined, isReviewingPrompt: false }))}
