                      >
                        {CAMERA_MODELS.map(m => <option key={m} value={m} className="bg-[#1a1a1a]">{m}</option>)}
                      </select>
                      <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-white/20">
