                  <div className="space-y-1">
                    <label className="text-[10px] text-white/40 ml-1 uppercase tracking-tight">Lens Optics</label>
                    <div className="relative">
                      <select 
                        value={state.camera.lens}
                        onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, lens: e.target.value }}))}
                        className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-2.5 lg:py-3 text-xs lg:text-sm focus:outline-none focus:border-indigo-500 transition-colors appearance-none text-white"
                      >
                        {LENSES.map(l => <option key={l} value={l} className="bg-[#1a1a1a]">{l}</option>)}
