      </main>

      {/* Footer Info */}
      <footer className="h-6 lg:h-8 border-t border-white/5 bg-[#080808] px-4 flex items-center justify-between text-[8px] lg:text-[10px] text-white/30 uppercase tracking-[0.2em] z-50">
        <div className="flex gap-2 lg:gap-4 truncate">
          <span>Gemini-2.5-Flash</span>
          <span className="text-white/10">|</span>
          <span className="truncate">Workflow: Prompt -> Review -> Render</span>
        </div>
        <div className="hidden sm:block">
          Alpha Release • 2024
        </div>
      </footer>

      {/* Sticky Bottom Generate Button for Mobile */}
      {!state.isReviewingPrompt && !state.generatedImage && (
        <div className="lg:hidden fixed bottom-6 right-6 z-[60]">
          <button
            onClick={handleGeneratePrompt}
            disabled={state.isGeneratingPrompt}
            className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 border-2 border-white/10 ${
              state.isGeneratingPrompt 
                ? 'bg-indigo-900 text-white/40 cursor-wait' 
                : 'bg-indigo-600 text-white hover:bg-indigo-500'
            }`}
          >
            {state.isGeneratingPrompt ? <Loader2 className="w-6 h-6 animate-spin" /> : <Wand2 className="w-6 h-6" />}
