};

export default App;

import React, { useState } from 'react';
import { Camera, Layers, Sun, Trash2, Download, Wand2, Loader2, Settings2, Copy, Check, X, FileText, RotateCw, Smartphone, Monitor } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS, SHOT_SCALES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import OrientationSlider from './components/OrientationSlider';
import ShotScalePicker from './components/ShotScalePicker';
import { generateDraftPrompt, generateStudioImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    camera: {
      model: CAMERA_MODELS[0],
      lens: LENSES[2],
      shotScale: SHOT_SCALES[3].label,
      orientation: 0,
    },
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    draftPrompt: '',
  });

  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl, mimeType },
      }
    }));
  };

  const handleRemove = (type: ReferenceType) => {
    setState(prev => ({
      ...prev,
      references: {
        ...prev.references,
        [type]: { ...prev.references[type], dataUrl: undefined, mimeType: undefined },
      }
    }));
  };

  const toggleLight = (index: number) => {
    setState(prev => {
      const newPositions = [...prev.lighting.positions];
      newPositions[index] = !newPositions[index];
      return { ...prev, lighting: { positions: newPositions } };
    });
  };

  const setThreePointLighting = () => {
    const newPositions = new Array(8).fill(false);
    newPositions[1] = true; 
    newPositions[7] = true; 
    newPositions[4] = true; 
    setState(prev => ({ ...prev, lighting: { positions: newPositions } }));
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    setError(null);
    try {
      const prompt = await generateDraftPrompt(state);
      setState(prev => ({ 
        ...prev, 
        draftPrompt: prompt, 
        isGeneratingPrompt: false, 
        isReviewingPrompt: true 
      }));
    } catch (err: any) {
      setError(err.message || "Failed to generate prompt.");
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    setError(null);
    try {
      const result = await generateStudioImage(state, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
      if (window.innerWidth < 1024) {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    } catch (err: any) {
      setError(err.message || "Generation failed.");
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(state.draftPrompt);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const downloadImage = () => {
    if (!state.generatedImage) return;
    const link = document.createElement('a');
    link.href = state.generatedImage;
    link.download = `studio-render-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col overflow-x-hidden">
      {/* Header */}
      <header className="border-b border-white/10 p-4 bg-[#0d0d0d]/90 backdrop-blur-md flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2 lg:gap-3">
          <div className="bg-indigo-600 p-1.5 lg:p-2 rounded-lg shadow-lg shadow-indigo-600/20">
            <Camera className="w-5 h-5 lg:w-6 lg:h-6 text-white" />
          </div>
          <div>
            <h1 className="text-sm lg:text-xl font-bold tracking-tight text-white leading-none">Cinematic Studio</h1>
            <p className="text-[8px] lg:text-xs text-white/40 uppercase tracking-widest mt-0.5 font-semibold">AI Render Engine</p>
          </div>
        </div>

        <div className="flex items-center gap-2 lg:gap-4">
          {error && <span className="hidden sm:inline text-red-400 text-xs animate-pulse truncate max-w-[150px]">{error}</span>}

          {!state.isReviewingPrompt && !state.generatedImage && (
            <button
              onClick={handleGeneratePrompt}
              disabled={state.isGeneratingPrompt}
              className={`flex items-center gap-2 px-4 lg:px-6 py-2 lg:py-2.5 rounded-full text-xs lg:text-sm font-semibold transition-all shadow-lg shadow-indigo-500/20 ${
                state.isGeneratingPrompt 
                  ? 'bg-white/5 text-white/40 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-500 text-white transform active:scale-95'
              }`}
            >
              {state.isGeneratingPrompt ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Wand2 className="w-4 h-4" />
              )}
              <span className="hidden xs:inline">{state.isGeneratingPrompt ? 'Analyzing Scene...' : 'Build Visual Script'}</span>
            </button>
          )}

          {state.isReviewingPrompt && (
            <button
              onClick={handleFinalRender}
              className="flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-bold bg-emerald-600 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-500/20 transform active:scale-95 transition-all animate-pulse"
            >
              <Check className="w-4 h-4" />
              <span>Finalize & Render</span>
            </button>
          )}

          {state.generatedImage && (
            <button
              onClick={() => setState(prev => ({ ...prev, generatedImage: undefined, isReviewingPrompt: false }))}
              className="flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-semibold bg-white/10 hover:bg-white/20 text-white transition-all"
            >
              <RotateCw className="w-4 h-4" />
              <span>Reset Studio</span>
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:flex-row lg:overflow-hidden">
        {/* Output Area */}
        <section className="order-1 lg:order-2 flex-1 bg-black relative flex flex-col items-center justify-center p-4 lg:p-8 min-h-[400px] lg:min-h-0">
          <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at center, #312e81 0%, transparent 70%)' }}></div>

          {/* 1. Initial Empty State */}
          {!state.isReviewingPrompt && !state.isGeneratingPrompt && !state.isGenerating && !state.generatedImage && (
            <div className="text-center max-w-md p-6 animate-in fade-in duration-700">
              <div className="w-16 h-16 lg:w-24 lg:h-24 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4 lg:mb-6 border border-white/10 shadow-inner">
                <Camera className="w-8 h-8 lg:w-10 lg:h-10 text-white/20" />
              </div>
              <h3 className="text-xl lg:text-2xl font-bold mb-2 text-white">Studio Floor</h3>
              <p className="text-white/40 text-xs lg:text-sm leading-relaxed mb-6">
                Upload your visual references and configure your studio setup to generate a cinematic masterpiece.
              </p>
              <div className="flex justify-center gap-4 text-[10px] uppercase tracking-widest text-white/20 font-bold">
                <span className="flex items-center gap-1"><Monitor className="w-3 h-3" /> Desktop Optimized</span>
                <span className="flex items-center gap-1"><Smartphone className="w-3 h-3" /> Touch Ready</span>
              </div>
            </div>
          )}

          {/* 2. Loading State (Prompt or Image) */}
          {(state.isGeneratingPrompt || state.isGenerating) && (
            <div className="flex flex-col items-center gap-4 lg:gap-6 z-10 text-center">
              <div className="relative">
                <div className="w-24 h-24 lg:w-32 lg:h-32 border-4 border-indigo-500/10 rounded-full"></div>
                <div className="w-24 h-24 lg:w-32 lg:h-32 border-t-4 border-indigo-500 rounded-full absolute top-0 animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="w-16 h-16 lg:w-20 lg:h-20 bg-indigo-500/10 rounded-full animate-pulse blur-xl"></div>
                   <Camera className="w-6 h-6 lg:w-8 lg:h-8 text-indigo-500 absolute animate-pulse" />
                </div>
              </div>
              <div className="space-y-1">
                <p className="text-lg lg:text-xl font-medium text-white tracking-wide">
                  {state.isGeneratingPrompt ? "Calculating Cinematic Vectors" : "Synthesizing Render"}
                </p>
                <p className="text-white/40 text-[10px] lg:text-xs animate-pulse font-mono">
                  {state.isGeneratingPrompt ? "Translating visual references into text..." : "Applying lighting maps and compositing..."}
                </p>
              </div>
            </div>
          )}

          {/* 3. Prompt Review State */}
          {state.isReviewingPrompt && (
            <div className="w-full max-w-2xl bg-[#0d0d0d] border border-white/10 rounded-2xl p-6 lg:p-8 shadow-2xl animate-in fade-in zoom-in-95 duration-300 z-10 mx-4">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-500/10 rounded-lg">
                    <FileText className="w-5 h-5 text-indigo-400" />
                  </div>
                  <h3 className="text-lg font-bold text-white">Visual Script</h3>
                </div>
                <button 
                  onClick={() => setState(prev => ({ ...prev, isReviewingPrompt: false }))}
                  className="p-1.5 hover:bg-white/5 rounded-lg text-white/20 hover:text-white transition-colors"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="relative group">
                <textarea
                  value={state.draftPrompt}
                  onChange={(e) => setState(prev => ({ ...prev, draftPrompt: e.target.value }))}
                  className="w-full h-48 lg:h-64 bg-black/40 border border-white/5 rounded-xl p-5 text-sm text-white/80 focus:outline-none focus:border-indigo-500/50 resize-none leading-relaxed font-mono custom-scrollbar"
                  placeholder="The script will appear here..."
                />
                <button 
                  onClick={copyToClipboard}
                  className="absolute top-3 right-3 p-2 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-white/40 hover:text-white transition-all backdrop-blur-sm"
                  title="Copy to clipboard"
                >
                  {copied ? <Check className="w-4 h-4 text-emerald-400" /> : <Copy className="w-4 h-4" />}
                </button>
              </div>

              <div className="mt-6 flex flex-col sm:flex-row items-center gap-4">
                <button 
                  onClick={handleFinalRender}
                  className="w-full sm:flex-1 py-3.5 px-6 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-bold transition-all shadow-lg shadow-indigo-500/20 active:scale-[0.98] flex items-center justify-center gap-2"
                >
                  <Wand2 className="w-4 h-4" /> Final Render
                </button>
                <button 
                  onClick={() => setState(prev => ({ ...prev, isReviewingPrompt: false }))}
                  className="w-full sm:w-auto py-3.5 px-6 bg-white/5 hover:bg-white/10 text-white/60 rounded-xl font-medium transition-all"
                >
                  Revise Setup
                </button>
              </div>
            </div>
          )}

          {/* 4. Final Image State */}
          {state.generatedImage && !state.isGenerating && (
            <div className="relative group w-full h-full flex flex-col items-center justify-center animate-in zoom-in-95 duration-500 px-4">
              <div className="max-w-full max-h-full rounded-2xl overflow-hidden shadow-2xl border border-white/10 bg-[#0d0d0d] relative">
                <img 
                  src={state.generatedImage} 
                  alt="Generated" 
                  className="max-w-full max-h-[60vh] lg:max-h-[75vh] object-contain block"
                />
                <div className="absolute inset-0 ring-1 ring-inset ring-white/10 pointer-events-none rounded-2xl"></div>
              </div>

              <div className="mt-6 flex gap-3 lg:absolute lg:bottom-12 lg:left-1/2 lg:-translate-x-1/2 lg:opacity-0 lg:group-hover:opacity-100 lg:transition-all lg:duration-300 lg:translate-y-4 lg:group-hover:translate-y-0">
                <button 
                  onClick={downloadImage}
                  className="flex items-center gap-2 bg-white text-black px-6 py-3 rounded-full text-sm font-bold hover:bg-white/90 transition-all shadow-xl active:scale-95"
                >
                  <Download className="w-4 h-4 lg:w-5 lg:h-5" />
                  Download 4K
                </button>
                <button 
                  onClick={() => setState(prev => ({ ...prev, generatedImage: undefined }))}
                  className="bg-white/10 backdrop-blur-md hover:bg-red-500/20 hover:text-red-400 text-white p-3 rounded-full transition-all border border-white/20 active:scale-95"
                >
                  <Trash2 className="w-5 h-5 lg:w-6 lg:h-6" />
                </button>
              </div>
            </div>
          )}
        </section>

        {/* Sidebar Controls */}
        <aside className="order-2 lg:order-1 w-full lg:w-[400px] border-t lg:border-t-0 lg:border-r border-white/10 bg-[#0d0d0d] flex flex-col shadow-2xl z-40">
          <div className="p-4 lg:p-6 space-y-8 overflow-y-auto max-h-none lg:max-h-full pb-24 lg:pb-12 scrollbar-hide">

            <section>
              <div className="flex items-center gap-2 mb-4">
                <Layers className="w-4 h-4 text-indigo-400" />
                <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Reference Library</h2>
              </div>
              <div className="grid grid-cols-3 lg:grid-cols-2 gap-2 lg:gap-3">
                {REFERENCE_SLOTS.map((slot) => (
                  <ReferenceUploader
                    key={slot.id}
                    slot={slot}
                    dataUrl={state.references[slot.id].dataUrl}
                    onUpload={(data, mime) => handleUpload(slot.id, data, mime)}
                    onRemove={() => handleRemove(slot.id)}
                  />
                ))}
              </div>
            </section>

            <section>
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <Sun className="w-4 h-4 text-amber-400" />
                  <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Lighting Rig</h2>
                </div>
                <button 
                  onClick={setThreePointLighting}
                  className="text-[9px] bg-white/5 hover:bg-indigo-500/20 text-white/60 hover:text-indigo-300 px-3 py-1.5 rounded-full transition-all border border-white/5 active:scale-95"
                >
                  Set 3-Point
                </button>
              </div>
              <div className="bg-black/40 rounded-3xl p-6 border border-white/5 shadow-inner">
                <LightRig 
                  activePositions={state.lighting.positions}
                  onToggle={toggleLight}
                  orientation={state.camera.orientation}
                />
                <div className="mt-8 grid grid-cols-4 gap-1.5">
                  {LIGHT_POSITIONS.map((lp, i) => (
                    <div key={i} className={`text-[8px] px-1 py-1 rounded-md text-center transition-all truncate border ${state.lighting.positions[i] ? 'bg-amber-500/10 text-amber-400 border-amber-500/30' : 'text-white/10 border-transparent'}`}>
                      {lp.label.split('-').map(s => s[0]).join('')}
                    </div>
                  ))}
                </div>
              </div>
            </section>

            <section>
              <div className="flex items-center gap-2 mb-4">
                <Settings2 className="w-4 h-4 text-emerald-400" />
                <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Camera Config</h2>
              </div>
              <div className="space-y-6">
                {/* Visual Scale Picker */}
                <div className="bg-black/40 rounded-3xl p-5 border border-white/5 shadow-inner">
                  <ShotScalePicker 
                    value={state.camera.shotScale}
                    onChange={(val) => setState(prev => ({ ...prev, camera: { ...prev.camera, shotScale: val }}))}
                  />
