                {/* Orientation Control */}
                <div className="bg-black/40 rounded-3xl p-6 border border-white/5 shadow-inner">
                  <OrientationSlider 
                    value={state.camera.orientation}
                    onChange={(val) => setState(prev => ({ ...prev, camera: { ...prev.camera, orientation: val }}))}
                  />
