                  <div className="space-y-2">
                    <label className="text-[9px] text-white/30 ml-1 uppercase font-bold tracking-widest">Digital Body</label>
                    <div className="relative group">
                      <select 
                        value={state.camera.model}
                        onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, model: e.target.value }}))}
                        className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-xs lg:text-sm focus:outline-none focus:border-indigo-500 transition-all appearance-none text-white cursor-pointer hover:bg-white/[0.07]"
                      >
                        {CAMERA_MODELS.map(m => <option key={m} value={m} className="bg-[#1a1a1a]">{m}</option>)}
                      </select>
                      <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-white/20 group-hover:text-white/40 transition-colors">
                        <Smartphone className="w-4 h-4" />
                      </div>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] text-white/30 ml-1 uppercase font-bold tracking-widest">Glass / Optics</label>
                    <div className="relative group">
                      <select 
                        value={state.camera.lens}
                        onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, lens: e.target.value }}))}
                        className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-xs lg:text-sm focus:outline-none focus:border-indigo-500 transition-all appearance-none text-white cursor-pointer hover:bg-white/[0.07]"
                      >
                        {LENSES.map(l => <option key={l} value={l} className="bg-[#1a1a1a]">{l}</option>)}
                      </select>
                      <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-white/20 group-hover:text-white/40 transition-colors">
                        <Monitor className="w-4 h-4" />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>
        </aside>
      </main>

      {/* Footer Info */}
      <footer className="h-8 border-t border-white/5 bg-[#080808] px-4 flex items-center justify-between text-[8px] lg:text-[10px] text-white/20 uppercase tracking-[0.3em] font-bold">
