import React, { useRef, useEffect } from 'react';
import { SubjectConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  onChange: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ subjectA, subjectB, activeCount, onChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  const handleInteract = (e: React.MouseEvent | React.TouchEvent, id: 'a' | 'b') => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    // Map click to grid coordinates
    const x = ((clientX - rect.left) / rect.width) * 200 - 100;
    const y = 100 - ((clientY - rect.top) / rect.height) * 100;

    onChange(id, { x: Math.max(-90, Math.min(90, x)), y: Math.max(5, Math.min(95, y)) });
  };

  const Marker = ({ id, config, color }: { id: 'a' | 'b', config: SubjectConfig, color: string }) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
    const top = `${100 - config.y}%`;

    return (
      <div 
        style={{ left, top }}
        className="absolute -translate-x-1/2 -translate-y-1/2 group cursor-move z-20"
        onMouseDown={(e) => handleInteract(e, id)}
      >
        {/* Rotation Handle */}
        <div 
          className="absolute -top-8 left-1/2 -translate-x-1/2 w-8 h-8 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
          onMouseDown={(e) => e.stopPropagation()}
        >
          <input 
            type="range" min="0" max="360" value={config.rotation} 
            onChange={(e) => onChange(id, { rotation: parseInt(e.target.value) })}
            className="w-12 h-1 accent-white rotate-0"
          />
        </div>

        {/* Character Icon */}
        <div className={`w-8 h-8 rounded-full border-2 border-white/40 flex items-center justify-center transition-transform ${color} shadow-xl shadow-black/50`}
             style={{ transform: `rotate(${config.rotation}deg)` }}>
          <div className="w-1.5 h-3 bg-white/80 rounded-full mb-1"></div>
          <div className="absolute top-0 w-1 h-2 bg-white rounded-full"></div>
        </div>
        <span className="absolute -bottom-5 left-1/2 -translate-x-1/2 text-[8px] font-bold text-white/50 uppercase whitespace-nowrap">
          Subject {id.toUpperCase()}
        </span>
      </div>
    );
  };

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center px-1">
        <label className="text-[10px] text-white/40 uppercase tracking-widest font-bold">Blocking / Floor Plan</label>
        <div className="flex gap-2">
          {[1, 2].map(num => (
            <button 
              key={num}
              onClick={() => onChange('a', { x: subjectA.x })} // Dummy to trigger refresh if needed, but we handle count in App
              className={`text-[9px] px-2 py-0.5 rounded border transition-colors ${activeCount === num ? 'bg-indigo-600 border-indigo-400' : 'bg-white/5 border-white/10'}`}
              style={{ pointerEvents: 'none' }} // Controlled by App state usually
            >
              {num}P
            </button>
          ))}
        </div>
      </div>

      <div 
        ref={containerRef}
        className="relative aspect-square bg-[#050505] rounded-2xl border border-white/10 overflow-hidden shadow-inner cursor-crosshair"
      >
        {/* Blueprint Grid */}
        <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

        {/* Camera FOV Cone */}
        <svg className="absolute bottom-0 left-1/2 -translate-x-1/2 w-full h-full pointer-events-none opacity-20" viewBox="0 0 100 100">
          <path d="M50 100 L0 0 L100 0 Z" fill="url(#fovGradient)" />
          <defs>
            <linearGradient id="fovGradient" x1="0" y1="1" x2="0" y2="0">
              <stop offset="0%" stopColor="#6366f1" />
              <stop offset="100%" stopColor="transparent" />
            </linearGradient>
          </defs>
        </svg>

        {/* Camera Icon */}
        <div className="absolute bottom-2 left-1/2 -translate-x-1/2 flex flex-col items-center gap-1 opacity-60">
          <div className="w-4 h-3 bg-white/20 border border-white/40 rounded-sm"></div>
          <span className="text-[6px] text-white font-bold uppercase tracking-tighter">Camera</span>
        </div>

        {/* Subjects */}
        <Marker id="a" config={subjectA} color="bg-indigo-500" />
        {activeCount === 2 && <Marker id="b" config={subjectB} color="bg-purple-500" />}
      </div>

      <p className="text-[8px] text-white/20 italic text-center px-4 leading-tight">
        Click grid to move subjects. Drag rotation sliders to face them toward the camera or each other.
