async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.4): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) { height = (maxWidth / width) * height; width = maxWidth; }
        else { width = (maxWidth / height) * width; height = maxWidth; }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  for (const [id, ref] of Object.entries(state.references)) {
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !id.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 320, 0.4);
      parts.push({ text: `REFERENCE_${id.toUpperCase()}: ${ref.label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    const horizontal = config.x < -30 ? "left" : config.x > 30 ? "right" : "center";
    const depth = config.y < 30 ? "foreground" : config.y > 60 ? "background" : "midground";
    return `Subject ${id.toUpperCase()} is positioned in the ${depth} ${horizontal}, rotated ${config.rotation} degrees.`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a Scene Director. Write a descriptive prompt based on this floor plan:
  ${getBlockingDesc('a')}
  ${state.subjects.activeCount === 2 ? getBlockingDesc('b') : ''}

  TECHNICAL:
  - Lens: ${state.camera.lens}
  - Frame: ${state.camera.shotScale}
  - Studio Lights: ${activeLights.join(', ') || 'Natural'}

  Describe the interaction and atmosphere. Ensure character integration into the background.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: "Synthesize this scene blocking into a cinematic prompt." }] },
    config: { systemInstruction, temperature: 0.8 }
  });

  return response.text?.trim() || "A cinematic scene.";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  for (const ref of Object.values(state.references)) {
    if (ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const prompt = `Render this exact multi-subject composition: ${finalPrompt}. 
  Focus on the specific spatial blocking and relative positioning of the characters. 
  Photorealistic, cinematic lighting, Arri Alexa quality.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [...parts, { text: prompt }] },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("No image data.");
  return `data:image/png;base64,${part.inlineData.data}`;
};

