import React, { useRef, useState, useEffect, useCallback, useMemo } from 'react';
import { SubjectConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  currentLens: string;
  onChange: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ subjectA, subjectB, activeCount, currentLens, onChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [draggingId, setDraggingId] = useState<'a' | 'b' | null>(null);

  // Map lens focal lengths to FOV angles (degrees)
  const fovAngle = useMemo(() => {
    const mmMatch = currentLens.match(/(\d+)mm/);
    const mm = mmMatch ? parseInt(mmMatch[1]) : 50;

    // Standard Full Frame equivalent FOV mapping
    if (mm <= 24) return 84;
    if (mm <= 35) return 63;
    if (mm <= 50) return 46;
    if (mm <= 85) return 28;
    return 46;
  }, [currentLens]);

  // Calculate FOV cone points for SVG
  const fovPoints = useMemo(() => {
    const halfAngleRad = (fovAngle / 2) * (Math.PI / 180);
    const topY = 0;
    const centerX = 50;
    const bottomY = 100;

    // Width at top of container (height = 100 units in SVG viewbox)
    const spread = Math.tan(halfAngleRad) * 100;
    return `${centerX - spread} ${topY}, ${centerX + spread} ${topY}, ${centerX} ${bottomY}`;
  }, [fovAngle]);

  const getGridCoords = useCallback((clientX: number, clientY: number) => {
    if (!containerRef.current) return { x: 0, y: 0 };
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 200 - 100;
    const y = 100 - ((clientY - rect.top) / rect.height) * 100;
    return {
      x: Math.max(-95, Math.min(95, x)),
      y: Math.max(5, Math.min(95, y))
    };
  }, []);

  const handleGlobalMove = useCallback((e: MouseEvent | TouchEvent) => {
    if (!draggingId) return;

    // Prevent scrolling on mobile while dragging
    if (e.cancelable) e.preventDefault();

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const coords = getGridCoords(clientX, clientY);
    onChange(draggingId, coords);
  }, [draggingId, getGridCoords, onChange]);

  const handleGlobalUp = useCallback(() => {
    setDraggingId(null);
  }, []);

  useEffect(() => {
    if (draggingId) {
      window.addEventListener('mousemove', handleGlobalMove);
      window.addEventListener('mouseup', handleGlobalUp);
      window.addEventListener('touchmove', handleGlobalMove, { passive: false });
      window.addEventListener('touchend', handleGlobalUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleGlobalMove);
      window.removeEventListener('mouseup', handleGlobalUp);
      window.removeEventListener('touchmove', handleGlobalMove);
      window.removeEventListener('touchend', handleGlobalUp);
    };
  }, [draggingId, handleGlobalMove, handleGlobalUp]);

  const startDragging = (e: React.MouseEvent | React.TouchEvent, id: 'a' | 'b') => {
    e.stopPropagation();
    setDraggingId(id);
  };

  const Marker = ({ id, config }: { id: 'a' | 'b', config: SubjectConfig }) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
