        >
           <div className="bg-black/90 backdrop-blur-xl px-2 py-0.5 rounded text-[8px] font-mono text-white mb-1 border border-white/20 shadow-xl">
            {config.rotation}°
           </div>
           <input 
            type="range" min="0" max="360" value={config.rotation} 
            onChange={(e) => onChange(id, { rotation: parseInt(e.target.value) })}
            className="w-16 h-1 accent-indigo-400 cursor-pointer"
