import { GoogleGenAI } from "@google/genai";
import { StudioState } from "../types";
import { LIGHT_POSITIONS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.4): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) { height = (maxWidth / width) * height; width = maxWidth; }
        else { width = (maxWidth / height) * width; height = maxWidth; }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  for (const [id, ref] of Object.entries(state.references)) {
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !id.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 320, 0.4);
      parts.push({ text: `REFERENCE_${id.toUpperCase()}: ${ref.label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  // Calculate focal length characteristics
  const mmMatch = state.camera.lens.match(/(\d+)mm/);
  const mm = mmMatch ? parseInt(mmMatch[1]) : 50;

  let opticsDesc = "";
  if (mm <= 24) opticsDesc = "Extreme wide-angle perspective. Noticeable barrel distortion at edges. Exaggerated distance between foreground and background. Deep depth of field.";
  else if (mm <= 35) opticsDesc = "Wide storyteller view. Strong environmental context with natural perspective depth.";
  else if (mm <= 55) opticsDesc = "Natural human-eye perspective. Balanced spatial relationships.";
  else if (mm >= 85) opticsDesc = "Telephoto compression. The background appears visually closer to the subjects. Shallow depth of field with creamy bokeh. Distances between characters appear flattened.";

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    // Translate Y (0-100) to meters (1m to 10m)
    const distanceMeters = (config.y / 10).toFixed(1);
    // Translate X (-100 to 100) to placement
    const horizontal = config.x < -40 ? "far-left" : config.x < -10 ? "left-of-center" : config.x > 40 ? "far-right" : config.x > 10 ? "right-of-center" : "dead-center";

    return `SUBJECT_${id.toUpperCase()} BLOCKING:
    - EXACT POSITION: ${distanceMeters} meters from the lens.
    - LATERAL POSITION: ${horizontal} (${config.x}% offset).
    - ROTATION: Facing ${config.rotation} degrees relative to camera (0 is facing away, 180 is facing lens).`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a Technical Director and Cinematographer. Your task is to write a highly specific RENDER SCRIPT. 

  MANDATORY SPATIAL REQUIREMENTS:
  1. ADHERE TO THE BLOCKING: You must explicitly mention the meter-distance and lateral placement for each character.
  2. ADHERE TO THE OPTICS: ${opticsDesc}
  3. INTEGRATE REFERENCES: Seamlessly blend the provided character, background, and prop references.

  SCENE CONFIGURATION:
  ${getBlockingDesc('a')}
  ${state.subjects.activeCount === 2 ? getBlockingDesc('b') : 'SINGLE SUBJECT SCENE'}

  LIGHTING RIG: ${activeLights.join(', ') || 'Natural/Ambient'}
  SHOT TYPE: ${state.camera.shotScale} on ${state.camera.model}

  Write the prompt in a professional, descriptive cinematic style. Do not use generic "nice image" phrases. Focus on geometry, light-falloff, and spatial accuracy.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: "Synthesize the technical script for this scene. Ensure the meter-distances and lens optics are the primary focus." }] },
    config: { systemInstruction, temperature: 0.7 }
  });

  return response.text?.trim() || "A cinematic scene.";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  for (const ref of Object.values(state.references)) {
    if (ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  // We reiterate the blocking in the final generation to ensure the image model doesn't drift.
  const prompt = `STRICT SPATIAL RENDER: ${finalPrompt}

  CRITICAL INSTRUCTIONS:
  - DO NOT move the characters. Keep the specific distances from camera as described.
  - Apply the exact lens distortion and spatial compression of a ${state.camera.lens} lens.
  - Maintain consistent lighting direction based on the described studio rig.
  - High-fidelity cinematic photography, 8k resolution, photorealistic textures.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [...parts, { text: prompt }] },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("No image data.");
  return `data:image/png;base64,${part.inlineData.data}`;
};

