  else if (mm <= 35) opticsDesc = "Wide storyteller view. Strong environmental context with natural perspective depth.";
  else if (mm <= 55) opticsDesc = "Natural human-eye perspective. Balanced spatial relationships.";
  else if (mm >= 85) opticsDesc = "Telephoto compression. The background appears visually closer to the subjects. Shallow depth of field with creamy bokeh. Distances between characters appear flattened.";

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    // Translate Y (0-100) to meters (1m to 10m). 0 is closest to lens, 100 is furthest.
    const distanceMeters = (config.y / 10).toFixed(1);
    // Translate X (-100 to 100) to placement. 0 is center.
    const horizontal = config.x < -40 ? "far-left" : config.x < -10 ? "left-of-center" : config.x > 40 ? "far-right" : config.x > 10 ? "right-of-center" : "dead-center";

    // Rotation mapping based on UI logic:
    // 0 = Facing Lens (Nose pointing down towards camera)
    // 90 = Profile (Facing screen-left)
    // 180 = Facing Away (Back to camera, facing into the background)
    // 270 = Profile (Facing screen-right)
    let orientationText = "";
    if (config.rotation >= 337.5 || config.rotation < 22.5) orientationText = "Facing directly towards the camera lens";
    else if (config.rotation >= 22.5 && config.rotation < 67.5) orientationText = "Facing three-quarters towards camera, looking slightly left";
    else if (config.rotation >= 67.5 && config.rotation < 112.5) orientationText = "In profile, looking to the screen-left";
    else if (config.rotation >= 112.5 && config.rotation < 157.5) orientationText = "Facing three-quarters away, looking back and left";
    else if (config.rotation >= 157.5 && config.rotation < 202.5) orientationText = "Facing directly away from the camera, into the background scene";
    else if (config.rotation >= 202.5 && config.rotation < 247.5) orientationText = "Facing three-quarters away, looking back and right";
    else if (config.rotation >= 247.5 && config.rotation < 292.5) orientationText = "In profile, looking to the screen-right";
    else orientationText = "Facing three-quarters towards camera, looking slightly right";

    return `SUBJECT_${id.toUpperCase()} BLOCKING:
    - EXACT POSITION: ${distanceMeters} meters away from the lens.
