import { GoogleGenAI } from "@google/genai";
import { StudioState } from "../types";
import { LIGHT_POSITIONS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.4): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) { height = (maxWidth / width) * height; width = maxWidth; }
        else { width = (maxWidth / height) * width; height = maxWidth; }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) {
    return "MANDATORY FRAMING: CLOSE-UP (CU). Frame the primary subject from the shoulders up. The head should dominate the frame. Focus intensely on facial features and expressions. Background must be heavily blurred and secondary.";
  }
  if (scale.includes("Medium Shot")) {
    return "MANDATORY FRAMING: MEDIUM SHOT (MS). Frame the subjects from the waist up. Capture upper body gestures and facial expressions clearly. Balanced relationship between subject and setting.";
  }
  if (scale.includes("Long Shot")) {
    return "MANDATORY FRAMING: LONG SHOT (LS). Full-body framing. The entire height of the subjects must be visible. The environment becomes a significant part of the composition.";
  }
  if (scale.includes("Wide Shot")) {
    return "MANDATORY FRAMING: WIDE SHOT (WS). Cinematic establishing view. Subjects are seen in full within a vast environmental context. Focus on the scale of the architecture or landscape.";
  }
  return "";
};

