import { GoogleGenAI } from "@google/genai";
import { StudioState } from "../types";
import { LIGHT_POSITIONS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.4): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) { height = (maxWidth / width) * height; width = maxWidth; }
        else { width = (maxWidth / height) * width; height = maxWidth; }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) {
    return "MANDATORY FRAMING: CLOSE-UP (CU). Frame from the shoulders up. Head occupies 70% of vertical space. Shallow focus.";
  }
  if (scale.includes("Medium Shot")) {
    return "MANDATORY FRAMING: MEDIUM SHOT (MS). Waist-up framing. Clear view of torso and hands.";
  }
  if (scale.includes("Long Shot")) {
    return "MANDATORY FRAMING: LONG SHOT (LS). Full-body framing. Subjects visible head-to-toe.";
  }
  if (scale.includes("Wide Shot")) {
    return "MANDATORY FRAMING: WIDE SHOT (WS). Subject is small in a large environment.";
  }
  return "";
};

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  for (const [id, ref] of Object.entries(state.references)) {
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !id.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 320, 0.4);
      parts.push({ text: `REFERENCE_${id.toUpperCase()}: This is the ${ref.label}.` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const mmMatch = state.camera.lens.match(/(\d+)mm/);
  const mm = mmMatch ? parseInt(mmMatch[1]) : 50;

  let opticsDesc = "";
  if (mm <= 24) opticsDesc = "ULTRA-WIDE ANGLE perspective. Deep focus, exaggerated depth.";
  else if (mm <= 35) opticsDesc = "WIDE ANGLE perspective. Environmental storytelling focus.";
  else if (mm <= 55) opticsDesc = "NATURAL 50mm perspective. Realistic spatial relationships.";
  else if (mm >= 85) opticsDesc = "TELEPHOTO COMPRESSION. Compressed background, extremely shallow depth of field.";

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    const distanceMeters = (config.y / 10).toFixed(1);
    const horizontal = config.x < -40 ? "far-left" : config.x < -10 ? "left-of-center" : config.x > 40 ? "far-right" : config.x > 10 ? "right-of-center" : "dead-center";

    // UI Logic: 0 faces lens (down), 180 faces away (up)
    let orientationText = "";
    if (config.rotation >= 337.5 || config.rotation < 22.5) orientationText = "Facing directly into camera lens";
    else if (config.rotation >= 22.5 && config.rotation < 67.5) orientationText = "Angled three-quarters towards camera-left";
    else if (config.rotation >= 67.5 && config.rotation < 112.5) orientationText = "In profile, looking to screen-left";
    else if (config.rotation >= 112.5 && config.rotation < 157.5) orientationText = "Angled three-quarters away towards back-left";
    else if (config.rotation >= 157.5 && config.rotation < 202.5) orientationText = "Facing directly away from the lens into the background";
    else if (config.rotation >= 202.5 && config.rotation < 247.5) orientationText = "Angled three-quarters away towards back-right";
    else if (config.rotation >= 247.5 && config.rotation < 292.5) orientationText = "In profile, looking to screen-right";
    else orientationText = "Angled three-quarters towards camera-right";

    return `SUBJECT_${id.toUpperCase()}: Positioned ${distanceMeters}m away from lens, ${horizontal} in frame, oriented: ${orientationText}.`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a World-Class Director of Photography. Generate a precise visual technical script.

ENVIRONMENT & LIGHTING INTEGRATION:
1. BACKGROUND ANALYSIS: Look at 'REFERENCE_BACKGROUND'. If it is abstract, less-photoreal, or stylized, translate it into a LOGICAL, PHOTOREALISTIC LANDSCAPE (e.g. an abstract red flow becomes a cinematic volcanic canyon or a high-tech neon data center).
2. LIGHT SOURCE: Identify the primary light source in the background reference. THE CHARACTERS MUST BE LIT BY THIS LIGHT. Describe the light interaction (shadows, highlights, rim lighting) on their skin and textures.
3. SUPPLEMENTAL LIGHTING: Integrate the following studio rig: ${activeLights.join(', ') || 'Global Illumination'}.

CAMERA & OPTICS:
- SHOT SCALE: ${getShotScaleInstructions(state.camera.shotScale)}
- VERTICAL ANGLE: ${state.camera.verticalAngle.toUpperCase()}. Adjust the horizon and subject eye-level accordingly.
- LENS: ${opticsDesc} (using a ${state.camera.model}).

BLOCKING:
${getBlockingDesc('a')}
${state.subjects.activeCount === 2 ? getBlockingDesc('b') : 'Single subject shot.'}

Write as a professional cinematic render script focusing on photorealistic textures and masterfully integrated lighting.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: "Analyze references and synthesize a script. Ensure the environment is upgraded to photoreal if needed and lighting is perfectly integrated." }] },
    config: { systemInstruction, temperature: 0.7 }
  });

  return response.text?.trim() || "A cinematic render.";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  const addRef = async (id: string, label: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `INPUT_REFERENCE_${id.toUpperCase()}: ${label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'ENVIRONMENT & PRIMARY LIGHT SOURCE REFERENCE. Render as high-fidelity photorealistic landscape.');
  await addRef('char_a', 'Subject A Appearance');
  await addRef('pose_a', 'Subject A Pose');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B Appearance');
    await addRef('pose_b', 'Subject B Pose');
  }
  await addRef('prop', 'Scene Object');

  const finalInstruction = `STRICT RENDER COMMAND:
  ${finalPrompt}

  HARD CONSTRAINTS:
  - LIGHTING: Subjects must be lit by the environment light source identified in the reference.
  - ENVIRONMENT: Convert abstract backgrounds to photorealistic landscapes.
  - FRAMING: STRICT ${state.camera.shotScale.toUpperCase()} (shoulder-up for Close Up).
  - PERSPECTIVE: ${state.camera.verticalAngle.toUpperCase()} view using a ${state.camera.lens}.
  - QUALITY: Photorealistic, 8k, masterfully blended, Arri Alexa aesthetics.`;

  parts.push({ text: finalInstruction });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("Render failed.");
  return `data:image/png;base64,${part.inlineData.data}`;
};

