    }
  }

  const mmMatch = state.camera.lens.match(/(\d+)mm/);
  const mm = mmMatch ? parseInt(mmMatch[1]) : 50;

  let opticsDesc = "";
  if (mm <= 24) {
    opticsDesc = "ULTRA-WIDE ANGLE (24mm). Exaggerate the background scale. Elements in the background should feel pushed away, vast, and extremely small. Deep focus (everything sharp). High barrel distortion at edges.";
  } else if (mm <= 35) {
    opticsDesc = "WIDE ANGLE (35mm). Natural storytelling perspective. The background should feel expansive but grounded.";
  } else if (mm <= 55) {
    opticsDesc = "STANDARD (50mm). Natural human-eye perspective. Realistic background scaling relative to subjects.";
  } else if (mm >= 85) {
    opticsDesc = "TELEPHOTO COMPRESSION (85mm). MANDATORY: The background must be TIGHTLY CROPPED. Elements from the background reference must appear significantly larger and visually 'pulled in' toward the subjects. Apply intense, creamy bokeh (background blur) to all distant objects.";
  }

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    const distanceMeters = (config.y / 10).toFixed(1);
    const horizontal = config.x < -40 ? "far-left" : config.x < -10 ? "left-of-center" : config.x > 40 ? "far-right" : config.x > 10 ? "right-of-center" : "dead-center";

    let orientationText = "";
    if (config.rotation >= 337.5 || config.rotation < 22.5) orientationText = "Facing directly into camera lens";
    else if (config.rotation >= 22.5 && config.rotation < 67.5) orientationText = "Angled three-quarters towards camera-left";
    else if (config.rotation >= 67.5 && config.rotation < 112.5) orientationText = "In profile, looking to screen-left";
    else if (config.rotation >= 112.5 && config.rotation < 157.5) orientationText = "Angled three-quarters away towards back-left";
    else if (config.rotation >= 157.5 && config.rotation < 202.5) orientationText = "Facing directly away from the lens into the background";
    else if (config.rotation >= 202.5 && config.rotation < 247.5) orientationText = "Angled three-quarters away towards back-right";
    else if (config.rotation >= 247.5 && config.rotation < 292.5) orientationText = "In profile, looking to screen-right";
    else orientationText = "Angled three-quarters towards camera-right";

    return `SUBJECT_${id.toUpperCase()}: Positioned ${distanceMeters}m away from lens, ${horizontal} in frame, oriented: ${orientationText}.`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a Professional Cinematographer and VFX Supervisor. Generate a precise visual technical script for an image generation model.

LENS & BACKGROUND LOGIC (CRITICAL):
- You must simulate a ${state.camera.lens} lens.
- IF THE LENS IS 85mm: You must CROP the background reference image. Elements should be much larger and blurred. This is called lens compression.
- IF THE LENS IS 24mm: You must EXPAND the background view. Elements should feel further away and sharper.
- ENVIRONMENT: If the 'REFERENCE_BACKGROUND' is abstract or low-fidelity, your script MUST convert it into a LOGICAL, PHOTOREALISTIC LANDSCAPE (e.g., abstract blue strokes become a cinematic high-tech laboratory or a twilight sky).

LIGHTING INTEGRATION:
- Identify the primary light source direction and color in the 'REFERENCE_BACKGROUND'.
- THE CHARACTERS MUST BE LIT BY THIS SOURCE. Describe how this light interacts with their skin (specular highlights, shadows, rim lights).
- Combine with the studio rig: ${activeLights.join(', ') || 'Global Cinematic Lighting'}.

CAMERA:
- SHOT SCALE: ${getShotScaleInstructions(state.camera.shotScale)}
- VERTICAL ANGLE: ${state.camera.verticalAngle.toUpperCase()}.
- OPTICS: ${opticsDesc}

BLOCKING:
${getBlockingDesc('a')}
${state.subjects.activeCount === 2 ? getBlockingDesc('b') : 'Single subject.'}

Write the response as a technical visual description. Focus on the interplay of lens physics, environmental lighting, and character placement.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: "Analyze the references and optics. Synthesize a script that integrates subjects perfectly, simulates the lens compression/expansion on the background, and ensures photorealistic lighting consistency." }] },
    config: { systemInstruction, temperature: 0.7 }
  });

  return response.text?.trim() || "A cinematic render.";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  const addRef = async (id: string, label: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `REFERENCE_ASSET: ${label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  // Important to provide background reference as the first visual context
  await addRef('background', 'Environment Reference. MUST be transformed based on lens focal length (crop/compress if 85mm, expand if 24mm).');
  await addRef('char_a', 'Subject A Appearance');
  await addRef('pose_a', 'Subject A Pose');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B Appearance');
    await addRef('pose_b', 'Subject B Pose');
  }
  await addRef('prop', 'Scene Object/Prop');

  const lensCompression = state.camera.lens.includes('85mm') 
    ? "PERFORM LENS COMPRESSION: Tighten the background framing significantly. Background elements should appear 3x larger and very close to the subject. Heavy bokeh."
    : state.camera.lens.includes('24mm')
    ? "PERFORM WIDE ANGLE EXPANSION: Distant background objects should look tiny and very far away. Deep field focus."
    : "Standard natural background framing.";

  const finalInstruction = `MANDATORY RENDER DIRECTIVE:
  ${finalPrompt}

  TECHNICAL REQUIREMENTS FOR RENDER:
  1. OPTICAL SIMULATION: ${lensCompression}
  2. LIGHTING HARMONY: Subjects must be physically lit by the lighting found in the background reference. Ensure correct light temperature and shadow direction.
  3. ENVIRONMENT: If background reference is abstract, render it as a logical, photorealistic cinematic landscape.
  4. FRAMING: STRICT ${state.camera.shotScale.toUpperCase()} (shoulder-up for Close Up).
  5. VERTICAL ANGLE: Render from ${state.camera.verticalAngle.toUpperCase()}.
  6. STYLE: 8k resolution, cinematic photography, Arri Alexa aesthetics, photorealistic skin and fabric textures.`;

  parts.push({ text: finalInstruction });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("Rendering system failed to generate image data.");
  return `data:image/png;base64,${part.inlineData.data}`;
};

import React, { useState } from 'react';
import { Camera, Layers, Sun, Trash2, Download, Wand2, Loader2, Settings2, Copy, Check, X, FileText, RotateCw, Monitor, UserPlus, UserMinus, ArrowUpDown, Compass, Code2 } from 'lucide-react';
