                  className="w-full h-full p-6 text-sm leading-relaxed font-mono focus:outline-none bg-transparent resize-none overflow-y-auto custom-scrollbar"
                  spellCheck={false}
                />
              </div>

              <div className="mt-8 flex gap-4">
                <button onClick={handleFinalRender} className="flex-1 py-4 bg-indigo-600 rounded-2xl font-bold hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20">Render Masterpiece</button>
                <button onClick={() => setState(prev => ({ ...prev, isReviewingPrompt: false }))} className="px-8 py-4 bg-white/5 rounded-2xl font-medium hover:bg-white/10 transition-all">Revise Settings</button>
