import { GoogleGenAI, Type } from "@google/genai";
import { StudioState } from "../types";
import { LIGHT_POSITIONS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.4): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) { height = (maxWidth / width) * height; width = maxWidth; }
        else { width = (maxWidth / height) * width; height = maxWidth; }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "MANDATORY FRAMING: CLOSE-UP (CU). Shoulder-up framing.";
  if (scale.includes("Medium Shot")) return "MANDATORY FRAMING: MEDIUM SHOT (MS). Waist-up framing.";
  if (scale.includes("Long Shot")) return "MANDATORY FRAMING: LONG SHOT (LS). Full-body framing.";
  if (scale.includes("Wide Shot")) return "MANDATORY FRAMING: WIDE SHOT (WS). Subject small in large environment.";
  return "";
};

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  for (const [id, ref] of Object.entries(state.references)) {
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !id.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 320, 0.4);
      parts.push({ text: `REFERENCE_${id.toUpperCase()}: ${ref.label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const mmMatch = state.camera.lens.match(/(\d+)mm/);
  const mm = mmMatch ? parseInt(mmMatch[1]) : 50;

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    const distanceMeters = (config.y / 10).toFixed(1);
    const horizontal = config.x < -40 ? "far-left" : config.x < -10 ? "left-of-center" : config.x > 40 ? "far-right" : config.x > 10 ? "right-of-center" : "dead-center";
    return `Subject ${id.toUpperCase()} at ${distanceMeters}m, ${horizontal} in frame, rotation ${config.rotation}°.`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a VFX Technical Director. Create a structured cinematic script.
  OUTPUT FORMAT: JSON ONLY.
  {
    "script": "A detailed technical prose describing the scene, lighting, and textures.",
    "technical_summary": "A concise summary of optics and lighting choices."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: `Generate script for ${state.camera.lens} ${state.camera.shotScale} from ${state.camera.verticalAngle}. Blocking: ${getBlockingDesc('a')} ${state.subjects.activeCount === 2 ? getBlockingDesc('b') : ''}. Lights: ${activeLights.join(', ')}.` }] },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          script: { type: Type.STRING },
          technical_summary: { type: Type.STRING }
        },
        required: ["script", "technical_summary"]
      }
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];

  const addRef = async (id: string, label: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `REFERENCE: ${label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'Environment & Lighting Foundation');
  await addRef('char_a', 'Subject A');
  await addRef('pose_a', 'Subject A Pose');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B');
    await addRef('pose_b', 'Subject B Pose');
  }
  await addRef('prop', 'Prop');

  const lensCompression = state.camera.lens.includes('85mm') 
    ? "LENS COMPRESSION: Crop background significantly, elements appear huge and blurred."
    : state.camera.lens.includes('24mm')
    ? "WIDE ANGLE: Expand field of view, background objects appear small and far."
    : "";

  const finalInstruction = `DIRECTIVE:
  ${finalPrompt}
  REQUIREMENTS:
  - Optics: ${state.camera.lens} from ${state.camera.verticalAngle}.
  - Framing: ${getShotScaleInstructions(state.camera.shotScale)}
  - Physics: ${lensCompression}
  - Quality: Photorealistic, 8k, Arri Alexa aesthetics.`;

  parts.push({ text: finalInstruction });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("Render engine failed.");
  return `data:image/png;base64,${part.inlineData.data}`;
};

