                <button onClick={() => setState(prev => ({ ...prev, generatedImage: undefined }))} className="p-3 bg-red-500/20 text-red-400 rounded-full border border-red-500/20 hover:bg-red-500 hover:text-white transition-all"><Trash2 className="w-6 h-6" /></button>
