              />

              <div className="space-y-3">
                 <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] text-white/40 uppercase tracking-tight font-semibold flex items-center gap-2">
                      <ArrowUpDown className="w-3 h-3" /> Vertical Angle
                    </label>
                 </div>
                 <select 
                  value={state.camera.verticalAngle}
                  onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, verticalAngle: e.target.value }}))}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs focus:outline-none focus:border-indigo-500"
                 >
                   {VERTICAL_ANGLES.map(a => <option key={a} value={a} className="bg-black">{a}</option>)}
                 </select>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-2">
                   <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest ml-1">Camera Body</label>
                   <select 
                    value={state.camera.model}
                    onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, model: e.target.value }}))}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs focus:outline-none focus:border-indigo-500"
                   >
                     {CAMERA_MODELS.map(m => <option key={m} value={m} className="bg-black">{m}</option>)}
                   </select>
                </div>
                <div className="space-y-2">
                   <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest ml-1">Lens Choice</label>
                   <select 
                    value={state.camera.lens}
                    onChange={(e) => setState(prev => ({ ...prev, camera: { ...prev.camera, lens: e.target.value }}))}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs focus:outline-none focus:border-indigo-500"
                   >
                     {LENSES.map(l => <option key={l} value={l} className="bg-black">{l}</option>)}
                   </select>
                </div>
              </div>
            </section>
          </div>
        </aside>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Eye, Monitor, Users, MoveRight, MoveLeft } from 'lucide-react';
import { SubjectConfig } from '../types';

interface GazeSelectorProps {
  subjectId: 'a' | 'b';
  config: SubjectConfig;
  otherSubject?: SubjectConfig;
  onChange: (val: number) => void;
}

const GazeSelector: React.FC<GazeSelectorProps> = ({ subjectId, config, otherSubject, onChange }) => {

  // Camera is at bottom (180 degrees world rotation)
  const setGazeToCamera = () => onChange(180);

  const setGazeToPartner = () => {
    if (!otherSubject) return;
    // Calculate angle between subjects
    const dx = otherSubject.x - config.x;
    const dy = otherSubject.y - config.y;
    // dy is flipped in standard floor planner coordinates relative to trig
    //dy = -dy; // Adjust for 100-y coordinate system

    // In our floorplanner, y=0 is bottom (near camera), y=100 is top (deep background)
    // atan2(y, x)
    const angleRad = Math.atan2(dx, otherSubject.y - config.y);
    let angleDeg = (angleRad * 180) / Math.PI;

    // Normalize to 0-360
    if (angleDeg < 0) angleDeg += 360;
    onChange(Math.round(angleDeg));
  };

  const PRESETS = [
    { label: 'Into Lens', icon: <Monitor className="w-3 h-3" />, action: setGazeToCamera },
    { label: 'Partner', icon: <Users className="w-3 h-3" />, action: setGazeToPartner, disabled: !otherSubject },
    { label: 'Left', icon: <MoveLeft className="w-3 h-3" />, action: () => onChange(270) },
    { label: 'Right', icon: <MoveRight className="w-3 h-3" />, action: () => onChange(90) },
  ];

  return (
    <div className="bg-black/40 p-3 lg:p-4 rounded-2xl border border-white/5 space-y-4">
      <div className="flex justify-between items-center px-0.5">
        <p className="text-[8px] font-bold text-white/30 uppercase">Subject {subjectId.toUpperCase()}</p>
        <span className="text-[8px] font-mono font-bold text-emerald-400 bg-emerald-500/10 px-1.5 py-0.5 rounded">
          {config.gaze}° Gaze
        </span>
      </div>

      <div className="grid grid-cols-2 gap-1.5">
        {PRESETS.map((p, i) => (
          <button
            key={i}
            onClick={p.action}
            disabled={p.disabled}
            className="flex items-center gap-2 px-2 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-[9px] font-bold text-white/40 hover:text-white/60 transition-all disabled:opacity-20 disabled:pointer-events-none"
          >
            {p.icon}
            {p.label}
          </button>
        ))}
      </div>

      <div className="relative h-1 bg-white/10 rounded-full">
        <input 
          type="range" 
          min="0" 
          max="360" 
          value={config.gaze} 
          onChange={(e) => onChange(parseInt(e.target.value))}
          className="absolute inset-0 w-full h-full appearance-none bg-transparent cursor-pointer accent-emerald-500"
        />
      </div>
    </div>
  );
};

export default GazeSelector;

