    <description>Full implementation of FloorPlanner with dragging logic, FOV visualization, and dual-axis (Body/Gaze) character indicators.</description>
    <content><![CDATA[import React, { useRef, useState, useEffect, useCallback, useMemo } from 'react';
import { Camera } from 'lucide-react';
import { SubjectConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  currentLens: string;
  onChange: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ subjectA, subjectB, activeCount, currentLens, onChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [draggingId, setDraggingId] = useState<'a' | 'b' | null>(null);

  const fovAngle = useMemo(() => {
    const mmMatch = currentLens.match(/(\d+)mm/);
    const mm = mmMatch ? parseInt(mmMatch[1]) : 50;
    // Standard full frame 36mm width sensor logic
    return 2 * Math.atan(18 / mm) * (180 / Math.PI);
  }, [currentLens]);

  const handleMouseDown = (id: 'a' | 'b') => (e: React.MouseEvent) => {
    e.preventDefault();
    setDraggingId(id);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!draggingId || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 200 - 100; // -100 to 100
    const y = 100 - ((e.clientY - rect.top) / rect.height) * 100; // 0 to 100

    onChange(draggingId, { 
      x: Math.max(-100, Math.min(100, x)), 
      y: Math.max(0, Math.min(100, y)) 
    });
  }, [draggingId, onChange]);

  const handleMouseUp = useCallback(() => {
    setDraggingId(null);
  }, []);

  useEffect(() => {
    if (draggingId) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [draggingId, handleMouseMove, handleMouseUp]);

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
    const top = `${100 - config.y}%`;

    return (
      <div 
        key={id}
        onMouseDown={handleMouseDown(id)}
        style={{ left, top }}
        className={`absolute -translate-x-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing z-20 group`}
      >
        <div className={`relative w-10 h-10 lg:w-12 lg:h-12 flex items-center justify-center transition-transform ${draggingId === id ? 'scale-110' : ''}`}>
          {/* Body Indicator - 0 is UP (Background), 180 is DOWN (Camera) */}
          <div 
            className="absolute inset-0 transition-transform duration-200"
            style={{ transform: `rotate(${config.rotation}deg)` }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-lg">
              <ellipse cx="50" cy="50" rx="35" ry="18" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="4" />
              <circle cx="50" cy="50" r="14" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
              {/* Nose points UP by default (0 degrees) */}
              <path d="M44 42 L50 32 L56 42 Z" fill={id === 'a' ? '#818cf8' : '#c084fc'} />
            </svg>
