              <ellipse cx="50" cy="50" rx="35" ry="18" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="4" />
              <circle cx="50" cy="50" r="14" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
              <path d="M44 42 L50 32 L56 42 Z" fill={id === 'a' ? '#818cf8' : '#c084fc'} />
            </svg>
          </div>

          {/* Gaze Indicator (Emerald Arrow) */}
          <div 
            className="absolute inset-0 pointer-events-none transition-transform duration-200"
            style={{ transform: `rotate(${config.gaze}deg)` }}
          >
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[160%] flex flex-col items-center">
                <div className="w-0.5 h-6 bg-gradient-to-t from-emerald-500 to-transparent rounded-full shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
                <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full -mt-1"></div>
             </div>
          </div>

          <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-[8px] font-black uppercase tracking-widest text-white/40 group-hover:text-white transition-colors whitespace-nowrap">
            {id === 'a' ? 'Sub A' : 'Sub B'}
          </div>
        </div>
      </div>
    );
  };

  return (
    <section className="space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Stage Blocking</h2>
        </div>
        <div className="flex gap-3">
          <div className="flex items-center gap-1">
            <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div>
            <span className="text-[7px] uppercase font-bold text-white/30">Body</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
            <span className="text-[7px] uppercase font-bold text-white/30">Gaze</span>
          </div>
        </div>
      </div>

      <div 
        ref={containerRef}
        className="relative aspect-square w-full bg-[#050505] rounded-3xl border border-white/5 overflow-hidden shadow-inner cursor-crosshair select-none"
      >
        {/* Grid */}
        <div className="absolute inset-0 opacity-5" style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '10% 10%' }}></div>

        {/* FOV Cone */}
        <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-10">
          <path 
            d={`M 50 100 L ${50 - Math.tan((fovAngle / 2) * Math.PI / 180) * 100} 0 L ${50 + Math.tan((fovAngle / 2) * Math.PI / 180) * 100} 0 Z`} 
            fill="url(#fovGrad)"
          />
          <defs>
            <linearGradient id="fovGrad" x1="0.5" y1="1" x2="0.5" y2="0">
              <stop offset="0%" stopColor="#6366f1" stopOpacity="0.8" />
              <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
            </linearGradient>
          </defs>
        </svg>

        {/* Camera Position */}
        <div className="absolute bottom-2 left-1/2 -translate-x-1/2 flex flex-col items-center z-30">
