import React, { useRef, useState, useEffect, useCallback, useMemo } from 'react';
import { Camera, RotateCw } from 'lucide-react';
import { SubjectConfig, CameraConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  cameras: CameraConfig[];
  activeCameraIndex: number;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  subjectA, 
  subjectB, 
  activeCount, 
  cameras, 
  activeCameraIndex,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragging, setDragging] = useState<{ type: 'subject' | 'camera'; id: any; offset?: { x: number; y: number } } | null>(null);

  const getFovAngle = (lens: string) => {
    const mmMatch = lens.match(/(\d+)mm/);
    const mm = mmMatch ? parseInt(mmMatch[1]) : 50;
    return 2 * Math.atan(18 / mm) * (180 / Math.PI);
  };

  const handleMouseDown = (type: 'subject' | 'camera', id: any) => (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (type === 'camera') onSelectCamera(id as number);
    setDragging({ type, id });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!dragging || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const rawX = ((e.clientX - rect.left) / rect.width) * 200 - 100;
    const rawY = 100 - ((e.clientY - rect.top) / rect.height) * 100;

    const x = Math.max(-100, Math.min(100, rawX));
    const y = Math.max(0, Math.min(100, rawY));

    if (dragging.type === 'subject') {
      onUpdateSubject(dragging.id, { x, y });
    } else {
      onUpdateCamera(dragging.id, { x, y });
    }
  }, [dragging, onUpdateSubject, onUpdateCamera]);

  const handleMouseUp = useCallback(() => {
    setDragging(null);
  }, []);

  useEffect(() => {
    if (dragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragging, handleMouseMove, handleMouseUp]);

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
    const top = `${100 - config.y}%`;

    return (
      <div 
        key={id}
        onMouseDown={handleMouseDown('subject', id)}
        style={{ left, top }}
        className="absolute -translate-x-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing z-20 group"
      >
        <div className={`relative w-10 h-10 flex items-center justify-center transition-transform ${dragging?.id === id ? 'scale-110' : ''}`}>
          <div 
            className="absolute inset-0 transition-transform duration-200"
            style={{ transform: `rotate(${config.rotation}deg)` }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-lg">
              <ellipse cx="50" cy="50" rx="35" ry="18" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="4" />
              <circle cx="50" cy="50" r="14" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
              <path d="M44 42 L50 32 L56 42 Z" fill={id === 'a' ? '#818cf8' : '#c084fc'} />
            </svg>
          </div>
          <div 
            className="absolute inset-0 pointer-events-none transition-transform duration-200"
            style={{ transform: `rotate(${config.gaze}deg)` }}
          >
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[160%] flex flex-col items-center">
                <div className="w-0.5 h-6 bg-gradient-to-t from-emerald-500 to-transparent rounded-full"></div>
                <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full -mt-1 shadow-sm"></div>
             </div>
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const left = `${((cam.x + 100) / 200) * 100}%`;
    const top = `${100 - cam.y}%`;
    const isActive = activeCameraIndex === index;
    const fov = getFovAngle(cam.lens);

    return (
      <div 
        key={cam.id}
        style={{ left, top }}
        onMouseDown={handleMouseDown('camera', index)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 z-30 group cursor-grab active:cursor-grabbing ${isActive ? 'z-40' : 'z-30'}`}
      >
        {/* FOV Cone for this camera */}
        <div 
          className="absolute inset-0 pointer-events-none transition-all duration-200"
          style={{ transform: `rotate(${cam.rotation}deg)`, opacity: isActive ? 0.3 : 0.05 }}
        >
          <svg className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-full w-[400px] h-[400px]">
             <path 
                d={`M 200 200 L ${200 - Math.tan((fov / 2) * Math.PI / 180) * 200} 0 L ${200 + Math.tan((fov / 2) * Math.PI / 180) * 200} 0 Z`} 
                fill="url(#fovGradient)"
              />
          </svg>
        </div>

        <div className={`relative p-2 rounded-xl border transition-all ${isActive ? 'bg-indigo-600 border-indigo-400 shadow-lg scale-110' : 'bg-black/80 border-white/20 hover:border-white/40 opacity-80'}`}>
          <div className="transition-transform duration-200" style={{ transform: `rotate(${cam.rotation}deg)` }}>
            <Camera className="w-4 h-4 text-white" />
          </div>
          <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black/60 px-1.5 py-0.5 rounded text-[7px] font-bold text-white/60 uppercase whitespace-nowrap">
            CAM {index + 1}
          </div>
        </div>
      </div>
    );
  };

  return (
    <section className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Stage Blocking</h2>
        <div className="flex gap-2">
           <span className="text-[7px] text-white/30 uppercase font-mono">X: {activeCameraIndex + 1} Cams Active</span>
        </div>
      </div>

      <div 
        ref={containerRef}
        className="relative aspect-square w-full bg-[#050505] rounded-3xl border border-white/5 overflow-hidden shadow-inner cursor-crosshair select-none"
      >
        {/* SVG Defs for FOV Gradient */}
        <svg className="absolute w-0 h-0">
          <defs>
            <linearGradient id="fovGradient" x1="0.5" y1="1" x2="0.5" y2="0">
              <stop offset="0%" stopColor="#6366f1" stopOpacity="0.8" />
              <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
            </linearGradient>
          </defs>
        </svg>

        {/* Grid */}
        <div className="absolute inset-0 opacity-5" style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '10% 10%' }}></div>

        {/* Subjects */}
        {renderSubject('a', subjectA)}
        {activeCount === 2 && renderSubject('b', subjectB)}

        {/* Cameras */}
        {cameras.map((cam, idx) => renderCamera(cam, idx))}
      </div>

      <div className="flex justify-between items-center px-1">
        <p className="text-[8px] text-white/20 uppercase tracking-widest italic">Drag cameras or subjects to compose the scene</p>
      </div>
    </section>
  );
};

