import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, CameraConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.4): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) { height = (maxWidth / width) * height; width = maxWidth; }
        else { width = (maxWidth / height) * width; height = maxWidth; }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "MANDATORY FRAMING: CLOSE-UP (CU). Shoulder-up framing.";
  if (scale.includes("Medium Shot")) return "MANDATORY FRAMING: MEDIUM SHOT (MS). Waist-up framing.";
  if (scale.includes("Long Shot")) return "MANDATORY FRAMING: LONG SHOT (LS). Full-body framing.";
  if (scale.includes("Wide Shot")) return "MANDATORY FRAMING: WIDE SHOT (WS). Subject small in large environment.";
  return "";
};

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  for (const [id, ref] of Object.entries(state.references)) {
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !id.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 320, 0.4);
      parts.push({ text: `REFERENCE_${id.toUpperCase()}: ${ref.label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    // Relative position to camera
    const dx = config.x - activeCamera.x;
    const dy = config.y - activeCamera.y;
    const dist = Math.sqrt(dx*dx + dy*dy).toFixed(1);

    return `Subject ${id.toUpperCase()} is at distance ${dist} relative to camera, body rotation ${config.rotation}°, gaze rotation ${config.gaze}°.`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a VFX Technical Director. Create a structured cinematic script for Gemini Image Generation.
  Consider the camera is at (${activeCamera.x}, ${activeCamera.y}) rotated ${activeCamera.rotation} degrees.
  OUTPUT FORMAT: JSON ONLY.
  {
    "script": "A detailed technical prose describing the scene, lighting, and textures based on the camera POV.",
    "technical_summary": "A concise summary of optics and lighting choices."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: `POV from Camera at (${activeCamera.x}, ${activeCamera.y}) rotation ${activeCamera.rotation}°. Lens: ${activeCamera.lens}, Shot: ${activeCamera.shotScale}, Angle: ${activeCamera.verticalAngle}. Blocking: ${getBlockingDesc('a')} ${state.subjects.activeCount === 2 ? getBlockingDesc('b') : ''}. Lights: ${activeLights.join(', ')}.` }] },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          script: { type: Type.STRING },
          technical_summary: { type: Type.STRING }
        },
        required: ["script", "technical_summary"]
      }
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  const addRef = async (id: string, label: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `REFERENCE: ${label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'Environment Foundation');
  await addRef('char_a', 'Subject A Visual');
  await addRef('pose_a', 'Subject A Pose Reference');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B Visual');
    await addRef('pose_b', 'Subject B Pose Reference');
  }
  await addRef('prop', 'Prop Details');

  const lensCompression = activeCamera.lens.includes('85mm') 
    ? "LENS COMPRESSION: High compression, background elements appear closer and creamy bokeh."
    : activeCamera.lens.includes('24mm')
    ? "WIDE ANGLE DISTORTION: Dynamic perspective, expanded field of view."
    : "";

  const finalInstruction = `DIRECTIVE:
  ${finalPrompt}
  TECHNICAL CONTEXT:
  - Camera: ${activeCamera.model}
  - Lens: ${activeCamera.lens} from ${activeCamera.verticalAngle}
  - Framing: ${getShotScaleInstructions(activeCamera.shotScale)}
  - Physics: ${lensCompression}
  - Final Aesthetic: Photorealistic cinematic master, 8k raw, professional grading.`;

  parts.push({ text: finalInstruction });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("Render engine failed.");
  return `data:image/png;base64,${part.inlineData.data}`;
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera } from 'lucide-react';
import { SubjectConfig, CameraConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  cameras: CameraConfig[];
  activeCameraIndex: number;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  subjectA, 
  subjectB, 
  activeCount, 
  cameras, 
  activeCameraIndex,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ type: 'subject' | 'camera'; id: any } | null>(null);

  // Stable references for handlers to avoid effect thrashing
  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });
  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mmMatch = lens.match(/(\d+)mm/);
    const mm = mmMatch ? parseInt(mmMatch[1]) : 50;
    // Standard full frame 36mm sensor width
    return 2 * Math.atan(18 / mm) * (180 / Math.PI);
  };

  const handleMouseDown = (type: 'subject' | 'camera', id: any) => (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (type === 'camera') handlersRef.current.onSelectCamera(id as number);
    setDragState({ type, id });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const rawX = ((e.clientX - rect.left) / rect.width) * 200 - 100;
    const rawY = 100 - ((e.clientY - rect.top) / rect.height) * 100;

    const x = Math.max(-100, Math.min(100, rawX));
    const y = Math.max(0, Math.min(100, rawY));

    if (dragState.type === 'subject') {
      handlersRef.current.onUpdateSubject(dragState.id, { x, y });
    } else {
      handlersRef.current.onUpdateCamera(dragState.id, { x, y });
    }
  }, [dragState]);

  const handleMouseUp = useCallback(() => {
    setDragState(null);
  }, []);

  useEffect(() => {
    if (dragState) {
      window.addEventListener('mousemove', handleMouseMove, { passive: true });
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, handleMouseMove, handleMouseUp]);

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
    const top = `${100 - config.y}%`;
    const isDragging = dragState?.type === 'subject' && dragState.id === id;

    return (
      <div 
        key={id}
        onMouseDown={handleMouseDown('subject', id)}
        style={{ left, top }}
        className={`absolute -translate-x-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing z-20 group select-none`}
      >
        <div className={`relative w-12 h-12 flex items-center justify-center transition-transform ${isDragging ? 'scale-125' : 'hover:scale-110'}`}>
          {/* Body */}
          <div 
            className="absolute inset-0 transition-transform duration-200"
            style={{ transform: `rotate(${config.rotation}deg)` }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-md">
              <ellipse cx="50" cy="50" rx="35" ry="18" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="4" />
              <circle cx="50" cy="50" r="14" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
              <path d="M44 42 L50 32 L56 42 Z" fill={id === 'a' ? '#818cf8' : '#c084fc'} />
            </svg>
          </div>
          {/* Gaze */}
          <div 
            className="absolute inset-0 pointer-events-none transition-transform duration-200"
            style={{ transform: `rotate(${config.gaze}deg)` }}
          >
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[180%] flex flex-col items-center">
                <div className="w-0.5 h-6 bg-gradient-to-t from-emerald-500 to-transparent rounded-full"></div>
                <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full -mt-1 shadow-[0_0_8px_rgba(52,211,153,0.5)]"></div>
             </div>
          </div>
          <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-[7px] font-black uppercase text-white/40 tracking-tighter whitespace-nowrap">
            SUB {id.toUpperCase()}
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const left = `${((cam.x + 100) / 200) * 100}%`;
    const top = `${100 - cam.y}%`;
    const isActive = activeCameraIndex === index;
    const isDragging = dragState?.type === 'camera' && dragState.id === index;
    const fov = getFovAngle(cam.lens);

    return (
      <div 
        key={cam.id}
        style={{ left, top }}
        onMouseDown={handleMouseDown('camera', index)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 select-none z-30 group cursor-grab active:cursor-grabbing ${isActive ? 'z-40' : 'z-20'}`}
      >
        {/* FOV Cone - Fixed alignment to center of icon */}
        <div 
          className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none transition-all duration-200"
          style={{ transform: `rotate(${cam.rotation}deg)`, opacity: isActive ? 0.35 : 0.08 }}
        >
          <svg className="w-[400px] h-[400px] -translate-y-1/2">
             <path 
                d={`M 200 200 L ${200 - Math.tan((fov / 2) * Math.PI / 180) * 200} 0 L ${200 + Math.tan((fov / 2) * Math.PI / 180) * 200} 0 Z`} 
                fill="url(#fovGradient)"
              />
          </svg>
        </div>

        <div className={`relative p-2.5 rounded-xl border transition-all ${isActive ? 'bg-indigo-600 border-indigo-300 shadow-xl scale-110' : 'bg-black/90 border-white/20 hover:border-white/40 opacity-70'}`}>
          <div className="transition-transform duration-200" style={{ transform: `rotate(${cam.rotation}deg)` }}>
            <Camera className="w-4 h-4 text-white" />
          </div>
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 bg-black/80 px-1.5 py-0.5 rounded text-[7px] font-bold text-white/80 uppercase whitespace-nowrap tracking-widest border border-white/10">
            CAM {index + 1}
          </div>
        </div>
      </div>
    );
  };

  return (
    <section className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Production Stage</h2>
        <div className="flex gap-2 text-[8px] font-mono text-white/20 uppercase">
          {cameras.length} Nodes Active
        </div>
      </div>

      <div 
        ref={containerRef}
        className="relative aspect-square w-full bg-[#050505] rounded-[2rem] border border-white/10 overflow-hidden shadow-2xl cursor-crosshair select-none"
        style={{ boxShadow: 'inset 0 0 60px rgba(0,0,0,0.8)' }}
      >
        {/* SVG Defs for FOV Gradient */}
        <svg className="absolute w-0 h-0">
          <defs>
            <linearGradient id="fovGradient" x1="0.5" y1="1" x2="0.5" y2="0">
              <stop offset="0%" stopColor="#818cf8" stopOpacity="0.9" />
              <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
            </linearGradient>
          </defs>
        </svg>

        {/* Dynamic Floor Grid */}
        <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

        {/* Background Visual Fade */}
        <div className="absolute inset-0 bg-gradient-to-b from-indigo-500/5 to-transparent pointer-events-none"></div>

        {/* Subjects */}
        {renderSubject('a', subjectA)}
        {activeCount === 2 && renderSubject('b', subjectB)}

        {/* Cameras */}
        {cameras.map((cam, idx) => renderCamera(cam, idx))}
      </div>

      <div className="flex justify-center items-center px-1">
        <p className="text-[7px] text-white/20 uppercase tracking-[0.3em] font-black">Spatial Mapping Matrix</p>
      </div>
    </section>
  );
};

export default FloorPlanner;

import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, CameraConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.4): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) { height = (maxWidth / width) * height; width = maxWidth; }
        else { width = (maxWidth / height) * width; height = maxWidth; }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "MANDATORY FRAMING: CLOSE-UP (CU). Shoulder-up framing.";
  if (scale.includes("Medium Shot")) return "MANDATORY FRAMING: MEDIUM SHOT (MS). Waist-up framing.";
  if (scale.includes("Long Shot")) return "MANDATORY FRAMING: LONG SHOT (LS). Full-body framing.";
  if (scale.includes("Wide Shot")) return "MANDATORY FRAMING: WIDE SHOT (WS). Subject small in large environment.";
  return "";
};

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  for (const [id, ref] of Object.entries(state.references)) {
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !id.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 320, 0.4);
      parts.push({ text: `REFERENCE_IMAGE_${id.toUpperCase()}: ${ref.label}` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    const dx = config.x - activeCamera.x;
    const dy = config.y - activeCamera.y;
    const dist = Math.sqrt(dx*dx + dy*dy).toFixed(1);

    return `Subject ${id.toUpperCase()} is at distance ${dist} relative to camera, body rotation ${config.rotation}°, gaze rotation ${config.gaze}°.`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a Senior Cinematic Technical Director. 
  Create a technical production script for Gemini Image Generation.

  SPATIAL EXPANSION RULE: 
  The camera is at (${activeCamera.x}, ${activeCamera.y}) with rotation ${activeCamera.rotation}°. 
  If this rotation or position looks away from the 'center' (0,0) of the environment, you MUST imaginatively expand and outpaint the environment edges to match the reference style.
  Imagine the unseen areas of the provided background reference to maintain consistency.

  OUTPUT FORMAT: JSON ONLY.
  {
    "script": "Technical prose describing the camera view, expanded environment, and subject positions.",
    "technical_summary": "Concise notes on optics and spatial expansion."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `TECHNICAL CONTEXT:
          Camera: Pos(${activeCamera.x}, ${activeCamera.y}), Rot(${activeCamera.rotation}°)
          Optics: Lens(${activeCamera.lens}), Scale(${activeCamera.shotScale})
          Blocking: ${getBlockingDesc('a')} ${state.subjects.activeCount === 2 ? getBlockingDesc('b') : ''}
          Lights: ${activeLights.join(', ')}

          TASK: Describe the POV precisely. If the rotation (${activeCamera.rotation}°) points towards the edges of the reference background, describe how the environment continues and expands naturally beyond the image border.` 
        }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          script: { type: Type.STRING },
          technical_summary: { type: Type.STRING }
        },
        required: ["script", "technical_summary"]
      }
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  const addRef = async (id: string, label: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `REFERENCE ASSET - ${label}:` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'Environment Blueprint');
  await addRef('char_a', 'Subject A Visual Identity');
  await addRef('pose_a', 'Subject A Kinetic Pose');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B Visual Identity');
    await addRef('pose_b', 'Subject B Kinetic Pose');
  }
  await addRef('prop', 'Essential Prop');

  const lensCompression = activeCamera.lens.includes('85mm') 
    ? "LENS COMPRESSION: Strong telephoto effect, shallow depth of field, background compression."
    : activeCamera.lens.includes('24mm')
    ? "WIDE PERSPECTIVE: Expanded spatial field, slight edge distortion for cinematic depth."
    : "";

  const finalInstruction = `PRODUCTION DIRECTIVE:
  ${finalPrompt}

  TECHNICAL OPTICS:
  - Format: Cinematic 16:9
  - Camera: ${activeCamera.model}
  - Lens: ${activeCamera.lens}
  - Angle: ${activeCamera.verticalAngle}
  - Framing: ${getShotScaleInstructions(activeCamera.shotScale)}
  - Spatial Expansion: Use the background reference as a core style, but extend it imaginatively to fill the 16:9 frame based on the ${activeCamera.rotation}° camera rotation.
  - Render: Ultra-photorealistic, 8k resolution, raw color profile, sharp focus on subjects.`;

  parts.push({ text: finalInstruction });

  const response = await ai.models.generateContent({
